window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["k"]={"Krzysztof": "<b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Kamil": "<b>Kamil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od rzymskiego imienia i <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognomenu</a> <i>Camillus</i> (słowo to jest tłumaczone z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> jako „pomocnik kapłana” bądź „zrodzony z wolnych rodziców”, „szlachetny chłopiec”).", "Kazimierz": "<b>Kazimierz</b> – współcześnie przyjęta forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> męskiego <b>Kazimir</b> (z odmiankami <b>Kazimirz</b>, <b>Kazimiar</b>, <b>Kazimier</b>, <b>Kaźmir</b>, <b>Kaźmisz</b>), składającego się z członów: <i>Kazi-</i> („niszcz, psuj, niwecz” od <i>kazić</i> „niszczyć, psuć”, porównaj współczesne <i>od-kazić</i> „od-psuć”) i <i>-mir</i> („pokój, spokój”). Oznacza „ten, który (niech) niszczy pokój” – niszcz pokój! = kaź mir! (staropolskie kazi mir!).", "Kacper": "<b>Kacper</b>, <b>Kasper</b>, <b>Kaspar</b>, <b>Gaspar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oboczności powstałe jako przekształcenie imienia Kasper, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> <i>ganzabara</i> („strażnik skarbca”) od <i>*ganzah</i> (“skarb”) + <i>*barah</i> (“brzemię”), od praindoeuropejskiego <i>*bʰer-</i> („brać”).", "Karol": "<b>Karol</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankijskiego</a> oznaczające człowieka mężnego lub wojownika. Staroskandynawskie znaczenie – „człowiek, mąż”. Imię jest również rozpowszechnione w krajach latynoskich.", "Krystian": "<b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Konrad": "<b>Konrad</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od staroniemieckiego słowa <i>kuoni</i> oznaczającego „odważny”, „śmiały”, „silny” oraz staroniemieckiego <i>rath</i> oznaczającego „radę”. Oznacza więc kogoś dającego dobre rady, dobrego doradcę. Imię rycerzy i książąt, przywędrowało do Polski w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a> z <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">Niemiec</a>.", "Ksawery": "<b>Ksawery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Pochodzi od nazwy miejscowości, z której pochodził <a href=\"https://pl.wikipedia.org/wiki/Franciszek_Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszek Ksawery</a> (<i>Javier</i>). Początkowo używane tylko w złożeniu z Franciszkiem (analogicznie do <a href=\"https://pl.wikipedia.org/wiki/Jan_Kanty\" target=\"_blank\" rel=\"noopener noreferrer\">Kantego</a>). Oboczna, bardziej archaiczna pisownia – <b>Xawery</b>.", "Kajetan": "<b>Kajetan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pierwotnie oznaczało „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Gaeta\" target=\"_blank\" rel=\"noopener noreferrer\">Caiety</a>”, miasta w <a href=\"https://pl.wikipedia.org/wiki/Italia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Italii</a>. Na Kresach imię to cieszyło się szczególną popularnością wśród mniejszości <a href=\"https://pl.wikipedia.org/wiki/Ormianie_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiej</a>.", "Kornel": "<b>Kornel</b>, <b>Korneliusz</b>, <b>Korneli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Cornelii</i> (<i>Korneliuszy</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusze Cynna</a>). Istnieją różne hipotezy pochodzenia wspomnianej nazwy rodowej; wywodzi się ją bądź to ze słowa <i>cornu</i> („róg”), bądź to <i>cornus</i> („<a href=\"https://pl.wikipedia.org/wiki/Dere%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dereń</a>”), bądź to od nazwy pola <i>Corne</i> w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. W dawnej Polsce zapisywane od <a href=\"https://pl.wikipedia.org/wiki/1402\" target=\"_blank\" rel=\"noopener noreferrer\">1402</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> formie <i>Cornelius</i> oraz od <a href=\"https://pl.wikipedia.org/wiki/1412\" target=\"_blank\" rel=\"noopener noreferrer\">1412</a> roku w formach pochodnych Kornosz, Kornasz, Korna (masc.), Kornosza (masc.), Kornoszek i ze zdrobnieniami Nela (masc.), Nelka (masc.), Nelko.", "Konstanty": "<b>Konstanty</b>, <b>Konstantyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> przydomka <i>Constantinus</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>constans</em> znaczącego „stały, stateczny, konsekwentny”. Żeńskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Konstantyna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantyna</a> lub <a href=\"https://pl.wikipedia.org/wiki/Konstancja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Konstancja</a>. W Polsce imię znane co najmniej od XV wieku.", "Klaudiusz": "<b>Klaudiusz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, pochodzące od nazwy <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskich</a> rodów <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudiuszy</a>; nazwa ta zaś wywodzi się od nazwy miasta <i>Clausus</i>, skąd oba rody Klaudiuszy wzięły początek. W Polsce imię Klaudiusz jest znane od <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>.", "Kordian": "<b>Kordian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone przez <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>. Oznacza <i>dający serce</i>. Kordian obchodzi imieniny <a href=\"https://pl.wikipedia.org/wiki/22_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">22 października</a>.", "Klemens": "<b>Klemens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „człowiek o łagodnym usposobieniu”, „delikatny”, „pobłażliwy”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Klemencja\" target=\"_blank\" rel=\"noopener noreferrer\">Klemencja</a>.", "Kewin": "<b>Kewin</b> – imię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, powstałe od imienia <i>Caoimhín</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroirlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">st. irl.</a> <i>Coemgen</i>), oznaczającego „ładny, przystojny”.", "Kasper": "<b>Kacper</b>, <b>Kasper</b>, <b>Kaspar</b>, <b>Gaspar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oboczności powstałe jako przekształcenie imienia Kasper, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> <i>ganzabara</i> („strażnik skarbca”) od <i>*ganzah</i> (“skarb”) + <i>*barah</i> (“brzemię”), od praindoeuropejskiego <i>*bʰer-</i> („brać”).", "Korneliusz": "Polska forma imienia obecna w tekście <i><a href=\"https://pl.wikipedia.org/wiki/Dzieje_Apostolskie\" target=\"_blank\" rel=\"noopener noreferrer\">Dziejów Apostolskich</a></i> jako imię <a href=\"https://pl.wikipedia.org/wiki/Korneliusz_(setnik_rzymski)\" target=\"_blank\" rel=\"noopener noreferrer\">setnika</a> z Cezarei (rozdz. 10): Korneliusz (<i><a href=\"https://pl.wikipedia.org/wiki/Biblia_Jakuba_Wujka\" target=\"_blank\" rel=\"noopener noreferrer\">Biblia Wujka</a></i>, 1599), Kornelijusz (<i><a href=\"https://pl.wikipedia.org/wiki/Biblia_gda%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Biblia gdańska</a></i>, 1632). Łacińska forma imienia <i>Cornēlius</i> została utrwalona w tekście greckim <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowego Testamentu</a> jako <i>Κορνήλιος</i> (<a href=\"https://pl.wikipedia.org/wiki/Koine\" target=\"_blank\" rel=\"noopener noreferrer\">koine</a>). Imię w tej formie wywodzi się od nazwy rzymskiego rodu <i>Cornelia</i> (<a href=\"https://pl.wikipedia.org/wiki/Gens\" target=\"_blank\" rel=\"noopener noreferrer\">gens</a> Cornelia). <i><a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">Nomen gentilicium</a></i> pochodziło od nazwy pola „Corne” w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. Podawane jest też w opracowaniach pochodzenie od <i>cornu</i> w znaczeniu „róg”. Wówczas imię oznaczałoby „słoneczny” (symbol królewski).", "Kryspin": "<b>Kryspin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie stanowiące zdrobnienie od łac. imienia męskiego <i>Crispus</i>, które powstało z przymiotnika oznaczającego „kędzierzawy”. Kryspin po raz pierwszy został poświadczony w Polsce w <a href=\"https://pl.wikipedia.org/wiki/1226\" target=\"_blank\" rel=\"noopener noreferrer\">1226</a> roku, w formach <i><b>Krzyszpin</b></i> i <i><b>Kryspin</b></i>. Możliwe staropolskie zdrobnienia to: Krzysz, Krzysza, Krzyszcz, Krzyszczek, Krzyszczko, Krzyszczk, Krzyszek, Krzyszka, Krzyszko, Krzyszna, Krzych, Krzychna.", "Kosma": "<b>Kosma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;κόσμος oznaczającego „porządek, ład”, „ozdobić”. Często wiązane z imieniem <a href=\"https://pl.wikipedia.org/wiki/Damian\" target=\"_blank\" rel=\"noopener noreferrer\">Damian</a> – od śś. <a href=\"https://pl.wikipedia.org/wiki/Kosma_i_Damian\" target=\"_blank\" rel=\"noopener noreferrer\">Kosmy i Damiana</a> (†283).", "Kasjan": "<b>Kasjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">rodu</a> <a href=\"https://pl.wikipedia.org/wiki/Republika_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> <i>Cassianus</i>. Imię to nosiło około dwunastu <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty\" target=\"_blank\" rel=\"noopener noreferrer\">świętych</a> lub <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiony\" target=\"_blank\" rel=\"noopener noreferrer\">błogosławionych</a>. W Polsce imię wystąpiło w 1445 roku jako Cassianus (Kasyjan). Później było rzadkie i ma niewielką popularność. W 2015 r. imię to nadano 27 chłopcom, w 2016 r. – 43, w 2017 r. – 61. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 1476 mężczyzn o imieniu Kasjan nadanym jako imię pierwsze.", "Kai": "<b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Karim": "<b>Karim</b> (<b>كريم</b>) – imię pochodzenia arabskiego, jest czterdziestym trzecim z „Najpiękniejszych imion Allaha”. Oznacza dosłownie „hojny”.", "Kristian": "<b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Krzesimir": "W Polsce imię Krzesimir jest łączone z chorwackim imieniem <b>Krešimir</b> lub <a href=\"https://pl.wikipedia.org/wiki/Hipokorystyk\" target=\"_blank\" rel=\"noopener noreferrer\">hipokorystycznie</a> <b>Krešo</b>, o podobnym lub takim samym pochodzeniu: od <i>kres-</i> (\"iskra, płomień, światło, ognisko\"). Niekiedy jednak przypisuje się mu nieco inną etymologię: od <i>kresiti</i>, czyli <i><a href=\"https://pl.wiktionary.org/wiki/krasiti\" target=\"_blank\" rel=\"noopener noreferrer\">krasiti</a></i>: 'ozdabiać, stroić'. W sensie przenośnym imię miało wyrażać życzenie rodziców, aby dziecko było spokojne, opanowane, zadowolone i cieszyło się pokojem. Czasem czasownik <i>krešati</i> tłumaczy się jako <i>walczyć</i>, a znaczenie całego imienia jako 'wojownik i władca'. Jeszcze indziej imię wiąże się z kultem świętego <a href=\"https://pl.wikipedia.org/wiki/Chryzogon_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">Krševana</a> (por. <a href=\"https://pl.wikipedia.org/wiki/Kr%C5%A1evan_Santini\" target=\"_blank\" rel=\"noopener noreferrer\">Krševan Santini</a>, <a href=\"https://pl.wikipedia.org/wiki/Chryzogon\" target=\"_blank\" rel=\"noopener noreferrer\">Chryzogon</a>).", "Krystyn": "<b>Krystyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> wywodzące się od wyrazu <a href=\"https://pl.wikipedia.org/wiki/Pomazaniec\" target=\"_blank\" rel=\"noopener noreferrer\">Pomazaniec</a> (<i>Chrystus</i>), do którego dodano przyrostek <i>-inus</i> wskazujący na zależność lub pochodzenie (<i>Christinus</i>, 'należący do Chrystusa, Chrystusowy'). W dokumentach polskich poświadczone w XI wieku w formie łacińskiej, a od XII w. w formie spolszczonej <i>Krystyn</i>.", "Kaj": "Na starożytność tego imienia wskazuje <a href=\"https://pl.wikipedia.org/wiki/Ortografia\" target=\"_blank\" rel=\"noopener noreferrer\">pisownia</a> jego skrótu, którym tradycyjnie było <i>C.</i> <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">Litera</a> ta pierwotnie oznaczała głoskę <i>g</i>, gdyż pochodziła ona od greckiej <i><a href=\"https://pl.wikipedia.org/wiki/Gamma\" target=\"_blank\" rel=\"noopener noreferrer\">Γ</a></i> (zaś litera <i>K</i> oznaczała głoskę <i>k</i>). Te dwie litery stosowano w ten właśnie sposób do roku <a href=\"https://pl.wikipedia.org/wiki/312_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">312 p.n.e.</a>, kiedy cenzor <a href=\"https://pl.wikipedia.org/wiki/Appiusz_Klaudiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Appiusz Klaudiusz</a> zmienił pisownię, wprowadzając literę <i>G</i> powstałą z przekształcenia <i>C</i>, a literze <i>C</i> nadał wartość głoski <i>k</i>. Oznacza to, że pisownia skrótu imienia <i>Gaius</i> utrwaliła się jeszcze przed reformą, a więc i samo imię musi pochodzić sprzed <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>", "Kilian": "<b>Kilian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, etymologicznie wiążące się ze słowem <i>gillean</i> „mnich”. Angielska, polska i niemiecka forma imienia <i>Cillian</i> pochodzi od słowa <i>ceallach</i> oznaczającego „wojna” lub <i>ceall</i> oznaczającego „kościół”. Istnieją zapisy tego imienia w Polsce pochodzące jeszcze ze średniowiecza.", "Kenan": "Księga Jubileuszów (rozdział 4) podaje również imię jego matki – Noam, imię jego żony i zarazem siostry – Melelet, oraz syna – Rasujal.", "Kalikst": "<b>Kalikst</b>, <b>Kalist</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od przymiotnika gr. 'kalós' (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Callistus, Callixtus</i>). Forma 'kállistos' oznacza 'bardzo dobry, bardzo piękny'.", "Kaleb": "<b>Kaleb</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> כָּלֵב) – postać biblijna ze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Jefunne_(potomek_Judy)\" target=\"_blank\" rel=\"noopener noreferrer\">Jefunnego</a>, ojciec Ira, Eli, Naama i Aksy. Był członkiem <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">izraelskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Pokolenie_Judy\" target=\"_blank\" rel=\"noopener noreferrer\">pokolenia Judy</a>, jedynym człowiekiem w wieku powyżej dwudziestu lat oprócz <a href=\"https://pl.wikipedia.org/wiki/Jozue\" target=\"_blank\" rel=\"noopener noreferrer\">Jozuego</a>, który w czasie czterdziestoletniej wędrówki do <a href=\"https://pl.wikipedia.org/wiki/Kanaan\" target=\"_blank\" rel=\"noopener noreferrer\">Kanaanu</a> opisanej w <a href=\"https://pl.wikipedia.org/wiki/Tora\" target=\"_blank\" rel=\"noopener noreferrer\">Torze</a> ani razu nie sprzeniewierzył się <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g_Ojciec\" target=\"_blank\" rel=\"noopener noreferrer\">Bogu</a>. Nagrodą za to był wstęp do <a href=\"https://pl.wikipedia.org/wiki/Ziemia_Obiecana_(Biblia)\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi Obiecanej</a> i przydział okolic <a href=\"https://pl.wikipedia.org/wiki/Hebron\" target=\"_blank\" rel=\"noopener noreferrer\">Hebronu</a> w dziedzictwo. Żył prawdopodobnie w <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">XIII</a>-<a href=\"https://pl.wikipedia.org/wiki/XII_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku p.n.e.</a> <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblia</a> nie podaje żadnych informacji o jego śmierci. Według tradycji żydowskiej umarł w mieście Jozuego Timnat-Serach. Od Kaleba pochodzi ród Kalebitów.", "Kasjusz": "<b>Kasjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodu</a>; ta z kolei być może stanowiła pierwotnie skrót z imienia złożonego takiego, jak <i>Cassignatus</i>, <i>Cassimara</i> czy <i>Cassisuratus</i>. Inną hipotezą jest pochodzenie tej nazwy rodowej od łacińskiego <i>cassus</i> – „pozbawiony czegoś, ogołocony z czegoś” lub też od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a> słowa, oznaczającego „biedny”. Imię to nosiło sześciu świętych.", "Kiejstut": "<b>Kiejstut</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">lit.</a> <i>Kęstutis</i> – cierpliwy, wytrwały) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Litwa\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a>.", "Kleofas": "<b>Kleofas</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało ono przez skrócenie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Κλεοπατρος (Kleopatros), które stanowi złożenie członów κλεος (<i>kleos</i>) „chwała, sława” i πατρος (<i>patros</i>) „ojca, ojcowska” (zob. też <a href=\"https://pl.wikipedia.org/wiki/Kleopatra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kleopatra</a>).", "Kaspar": "<b>Kacper</b>, <b>Kasper</b>, <b>Kaspar</b>, <b>Gaspar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oboczności powstałe jako przekształcenie imienia Kasper, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> <i>ganzabara</i> („strażnik skarbca”) od <i>*ganzah</i> (“skarb”) + <i>*barah</i> (“brzemię”), od praindoeuropejskiego <i>*bʰer-</i> („brać”).", "Kirył": "<b>Cyryl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>. Wywodzi się ze słowa κύριος znaczącego „pan”, „władca”. W Polsce używane było rzadko, częściej natomiast na Rusi Czerwonej.", "Kenji": "<b>Kenji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けんじ, ケンジ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kajus": "Na starożytność tego imienia wskazuje <a href=\"https://pl.wikipedia.org/wiki/Ortografia\" target=\"_blank\" rel=\"noopener noreferrer\">pisownia</a> jego skrótu, którym tradycyjnie było <i>C.</i> <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">Litera</a> ta pierwotnie oznaczała głoskę <i>g</i>, gdyż pochodziła ona od greckiej <i><a href=\"https://pl.wikipedia.org/wiki/Gamma\" target=\"_blank\" rel=\"noopener noreferrer\">Γ</a></i> (zaś litera <i>K</i> oznaczała głoskę <i>k</i>). Te dwie litery stosowano w ten właśnie sposób do roku <a href=\"https://pl.wikipedia.org/wiki/312_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">312 p.n.e.</a>, kiedy cenzor <a href=\"https://pl.wikipedia.org/wiki/Appiusz_Klaudiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Appiusz Klaudiusz</a> zmienił pisownię, wprowadzając literę <i>G</i> powstałą z przekształcenia <i>C</i>, a literze <i>C</i> nadał wartość głoski <i>k</i>. Oznacza to, że pisownia skrótu imienia <i>Gaius</i> utrwaliła się jeszcze przed reformą, a więc i samo imię musi pochodzić sprzed <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>", "Kwame": "<b>Kwame</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_twi\" target=\"_blank\" rel=\"noopener noreferrer\">języka twi</a> używanego w <a href=\"https://pl.wikipedia.org/wiki/Ghana\" target=\"_blank\" rel=\"noopener noreferrer\">Ghanie</a>.", "Kastor": "<b>Kastor</b> – polska forma zlatynizowanego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Castor</i> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>kekasmai</i> oznaczającego \"świecić\". W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> Kastor był synem <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>. Istnieją święci katoliccy o tym imieniu.", "Ke": "<b>Ќ</b>, <b>ќ</b> – litera <a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylicy</a> używana w alfabecie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka macedońskiego</a> oznaczająca /kj/. Często odpowiada <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%C4%86\" target=\"_blank\" rel=\"noopener noreferrer\">Ć</a>/<a href=\"https://pl.wikipedia.org/wiki/%D0%8B\" target=\"_blank\" rel=\"noopener noreferrer\">Ћ</a>, a niekiedy także np. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiemu</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/C\" target=\"_blank\" rel=\"noopener noreferrer\">C</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">rosyjskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%A7\" target=\"_blank\" rel=\"noopener noreferrer\">Ч</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%A9\" target=\"_blank\" rel=\"noopener noreferrer\">Щ</a>.", "Kang": "Pierwszy znany piec typu kang, z jednym kanałem dymowym, pochodzi z I wieku n.e. z terenów prowincji <a href=\"https://pl.wikipedia.org/wiki/Heilongjiang\" target=\"_blank\" rel=\"noopener noreferrer\">Heilongjiang</a>.", "Karo": "W oficjalnych turniejowych taliach kart do gry w <a href=\"https://pl.wikipedia.org/wiki/Skat\" target=\"_blank\" rel=\"noopener noreferrer\">skata</a> kara są koloru <a href=\"https://pl.wikipedia.org/wiki/Barwa_%C5%BC%C3%B3%C5%82ta\" target=\"_blank\" rel=\"noopener noreferrer\">żółtego</a> lub <a href=\"https://pl.wikipedia.org/wiki/Barwa_pomara%C5%84czowa\" target=\"_blank\" rel=\"noopener noreferrer\">pomarańczowego</a> <a href=\"https://pl.wikipedia.org/wiki/Plik:SuitDiamonds4colors.svg\" target=\"_blank\" rel=\"noopener noreferrer\"></a>. Jest to spowodowane turniejową unifikacją dwóch rodzajów talii – typu francuskiego i <a href=\"https://pl.wikipedia.org/wiki/Karty_polskie\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a>, gdyż odpowiednik kar w tym drugim typie – dzwonek – jest oznaczany kolorowym (głównie <a href=\"https://pl.wikipedia.org/wiki/Barwa_z%C5%82ota\" target=\"_blank\" rel=\"noopener noreferrer\">złotym</a>) dzwonkiem.", "Khazar": "<b>Chazarowie</b>, Kozarowie (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">tur.</a>&#160;<em>Hazarlar</em>) – <a href=\"https://pl.wikipedia.org/wiki/Koczownik\" target=\"_blank\" rel=\"noopener noreferrer\">lud koczowniczy</a> <a href=\"https://pl.wikipedia.org/wiki/Ludy_tureckie\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia tureckiego</a>, o którym pierwsze wzmianki pochodzą z VI wieku n.e. Tereny zajmowane przez Chazarów rozciągały się na <a href=\"https://pl.wikipedia.org/wiki/Step_Pontyjski\" target=\"_blank\" rel=\"noopener noreferrer\">Stepie Pontyjsko-Kaspijskim</a> między północnym <a href=\"https://pl.wikipedia.org/wiki/Kaukaz_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Kaukazem</a>, <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82wysep_Krymski\" target=\"_blank\" rel=\"noopener noreferrer\">Krymem</a>, <a href=\"https://pl.wikipedia.org/wiki/Morze_Kaspijskie\" target=\"_blank\" rel=\"noopener noreferrer\">Morzem Kaspijskim</a> a rzeką <a href=\"https://pl.wikipedia.org/wiki/Ural_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">Jaik</a> i <a href=\"https://pl.wikipedia.org/wiki/Samara_(dop%C5%82yw_Wo%C5%82gi)\" target=\"_blank\" rel=\"noopener noreferrer\">Samarą</a>. Trudnili się głównie pasterstwem i handlem, a bogacili na łupieskich wyprawach. Przez ich ziemie prowadziły największe szlaki handlowe z Chin do Europy (<a href=\"https://pl.wikipedia.org/wiki/Jedwabny_szlak\" target=\"_blank\" rel=\"noopener noreferrer\">jedwabny szlak</a>, szlak <a href=\"https://pl.wikipedia.org/wiki/Radanici\" target=\"_blank\" rel=\"noopener noreferrer\">radanitów</a>) oraz szlak północ-południe (<a href=\"https://pl.wikipedia.org/wiki/Od_Wareg%C3%B3w_do_Grek%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">od Waregów do Greków</a>).", "Kei": "<b>Kei</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けい, ケイ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>, coraz częściej stosowane jako żeńskie imię – jako skrót od <a href=\"https://pl.wikipedia.org/wiki/Keiko\" target=\"_blank\" rel=\"noopener noreferrer\">Keiko</a>.", "Kaito": "<b>Kaito</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;海斗, 海翔, 海人, 快斗, 凱斗) lub <b>Kaitō</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;怪盗) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Keisuke": "<b>Keisuke</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けいすけ, ケイスケ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Kyu": "W go różnica 1 kyū oznacza 1 kamień <a href=\"https://pl.wikipedia.org/wiki/Handicap_(go)\" target=\"_blank\" rel=\"noopener noreferrer\">handicapu</a> dla słabszego gracza.", "Krzysław": "<b>Krzesisław</b>, <b>Krzecsław</b>, <b>Krzesław</b>, <b>Krzysław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sław</i> („sława”). Znaczenie imienia: „odnawiający sławę”.", "Korneli": "<b>Kornel</b>, <b>Korneliusz</b>, <b>Korneli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Cornelii</i> (<i>Korneliuszy</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusze Cynna</a>). Istnieją różne hipotezy pochodzenia wspomnianej nazwy rodowej; wywodzi się ją bądź to ze słowa <i>cornu</i> („róg”), bądź to <i>cornus</i> („<a href=\"https://pl.wikipedia.org/wiki/Dere%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dereń</a>”), bądź to od nazwy pola <i>Corne</i> w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. W dawnej Polsce zapisywane od <a href=\"https://pl.wikipedia.org/wiki/1402\" target=\"_blank\" rel=\"noopener noreferrer\">1402</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> formie <i>Cornelius</i> oraz od <a href=\"https://pl.wikipedia.org/wiki/1412\" target=\"_blank\" rel=\"noopener noreferrer\">1412</a> roku w formach pochodnych Kornosz, Kornasz, Korna (masc.), Kornosza (masc.), Kornoszek i ze zdrobnieniami Nela (masc.), Nelka (masc.), Nelko.", "Konstancjusz": "<b>Konstancjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>constans</i> oznaczającego „stały”, „prawidłowy”. Jego patronem jest św. Konstancjusz, biskup (<a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wiek</a>).", "Kazuki": "<b>Kazuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずき, カズキ) – głównie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, rzadko noszone przez kobiety.", "Krzesisław": "<b>Krzesisław</b>, <b>Krzecsław</b>, <b>Krzesław</b>, <b>Krzysław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sław</i> („sława”). Znaczenie imienia: „odnawiający sławę”.", "Krzesław": "<b>Krzesisław</b>, <b>Krzecsław</b>, <b>Krzesław</b>, <b>Krzysław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sław</i> („sława”). Znaczenie imienia: „odnawiający sławę”.", "Klaudian": "<b>Klaudian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od nazwy rzymskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudiuszów</a> przy pomocy <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ianus</i>, oznaczającego przynależność lub pochodzenie. Patronem tego imienia jest św. Klaudian, wspominany razem ze św. Wiktorem, Wiktorynem, Papiaszem, Serapionem, Dioskurem i Niceforem.", "Krum": "<b>Krum</b> (Korum) <b>Zwycięzca</b> lub <b>Straszny</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułg.</a> Кана Субиги Крум Страшни (ur.&#160;?, zm. <a href=\"https://pl.wikipedia.org/wiki/814\" target=\"_blank\" rel=\"noopener noreferrer\">814</a>) – kolejny władca <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a> po <a href=\"https://pl.wikipedia.org/wiki/Chan_(w%C5%82adca)\" target=\"_blank\" rel=\"noopener noreferrer\">chanie</a> <a href=\"https://pl.wikipedia.org/wiki/Kardam\" target=\"_blank\" rel=\"noopener noreferrer\">Kardamie</a> oraz założyciel nowej dynastii. Jego ród prawdopodobnie wywodził się z <a href=\"https://pl.wikipedia.org/wiki/Protobu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">Protobułgarów</a> <a href=\"https://pl.wikipedia.org/wiki/Panonia\" target=\"_blank\" rel=\"noopener noreferrer\">panońskich</a>. Był pierwszym władcą noszącym tytuł <i>chan subigi</i>.", "Kazuo": "<b>Kazuo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずお, カズオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kazuma": "<b>Kazuma</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずま, カズマ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kelwin": "<b>Kelwin</b> – jednostka <a href=\"https://pl.wikipedia.org/wiki/Temperatura\" target=\"_blank\" rel=\"noopener noreferrer\">temperatury</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">układzie SI</a>, oznaczana symbolem <b>K</b>. Nazwa pochodzi od brytyjskiego fizyka <a href=\"https://pl.wikipedia.org/wiki/William_Thomson\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Thomsona, lorda Kelvina</a>.", "Kazuhiro": "<b>Kazuhiro</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずひろ, カズヒロ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Keiichi": "<b>Keiichi</b> lub <b>Kei'ichi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けいいち, ケイイチ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kabil": "Kabil pochodził z <a href=\"https://pl.wikipedia.org/wiki/Plemi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">plemienia</a> <a href=\"https://pl.wikipedia.org/wiki/Banu\" target=\"_blank\" rel=\"noopener noreferrer\">Banu</a>. Jego historia podana została w dziele <a href=\"https://pl.wikipedia.org/wiki/Hiszam_Ibn_Al-Kalbi\" target=\"_blank\" rel=\"noopener noreferrer\">Ibn al-Kalbiego</a>.", "Kourosh": "<b>Kourosh</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;کوروش، کورش&#8206;, wymawiany również Koorosh lub Kurosh) – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie popularne na terenie <a href=\"https://pl.wikipedia.org/wiki/Iran\" target=\"_blank\" rel=\"noopener noreferrer\">Iranu</a>. Pochodzi od imienia <a href=\"https://pl.wikipedia.org/wiki/Cyrus\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrus</a>.", "Kenta": "<b>Kenta</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けんた, ケンタ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kant": "Kant otwiera poczet klasycznych <a href=\"https://pl.wikipedia.org/wiki/Idealizm_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">idealistów niemieckich</a>; do kantyzmu odwoływały się też <a href=\"https://pl.wikipedia.org/wiki/Neokantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">neokantyzm</a> (kontynuacja), <a href=\"https://pl.wikipedia.org/wiki/Fenomenologia\" target=\"_blank\" rel=\"noopener noreferrer\">fenomenologia</a> (rewizja) oraz <a href=\"https://pl.wikipedia.org/wiki/Pozytywizm_logiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pozytywizm logiczny</a> (opozycja). Z tego ostatniego wywodzi się bliższy Kantowi <a href=\"https://pl.wikipedia.org/wiki/Popperyzm\" target=\"_blank\" rel=\"noopener noreferrer\">popperyzm</a> znany też jako <a href=\"https://pl.wikipedia.org/wiki/Krytyczny_racjonalizm\" target=\"_blank\" rel=\"noopener noreferrer\">krytyczny racjonalizm</a>. Kantyzm wywarł też wpływ na szkoły i kierunki, z którymi kontrastował; tomizm to <a href=\"https://pl.wikipedia.org/wiki/System_filozoficzny\" target=\"_blank\" rel=\"noopener noreferrer\">system filozoficzny</a> oparty na epistemologii realistycznej i dążący do wiedzy drogą metafizyki, jednak jedną z postaci <a href=\"https://pl.wikipedia.org/wiki/Neotomizm\" target=\"_blank\" rel=\"noopener noreferrer\">neotomizmu</a> jest <a href=\"https://pl.wikipedia.org/wiki/Tomizm_transcendentalizuj%C4%85cy\" target=\"_blank\" rel=\"noopener noreferrer\">tomizm transcendentalizujący</a>.", "Kunibert": "<b>Kunibert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „dzielny i lśniący, jaśniejący”, od germ. <i>kuoni</i> – „dzielny, odważny”, i <i>beraht</i> – „jasny, lśniący”. Patronem tego imienia jest św. Kunibert, biskup <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (VII wiek).", "Koriun": "<b>Koriun</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiański</a> Կորյուն lub Կորիւն) – pierwszy dziejopisarz używający języka ormiańskiego. Jego dzieło <i>Żywot Mesropa</i> zawiera wiele informacji dotyczących ewangelizacji <a href=\"https://pl.wikipedia.org/wiki/Armenia\" target=\"_blank\" rel=\"noopener noreferrer\">Armenii</a> i stworzenia <a href=\"https://pl.wikipedia.org/wiki/Alfabet\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiego</a>. Niektórzy współcześni historycy uważają, że Koriun był z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gruzini\" target=\"_blank\" rel=\"noopener noreferrer\">Gruzinem</a> (<a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Iberii\" target=\"_blank\" rel=\"noopener noreferrer\">Iberia Kaukaska</a> lub miał mieszane pochodzenie, gruzińsko- <a href=\"https://pl.wikipedia.org/wiki/Ormianie\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskie</a>. Koriun był wychowankiem <a href=\"https://pl.wikipedia.org/wiki/Mesrop_Masztoc\" target=\"_blank\" rel=\"noopener noreferrer\">Mesropa Masztoca</a>. Wiadomo że nauki pobierał również w <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Bizancjum</a> a do Armenii powrócił w 432 roku. Był bliskim przyjacielem Eznika z Kolb. Został mianowany biskupem Iberii i oprócz pracy duszpasterskiej i misjonarskiej zajmował się także przekładami na język ormiański. Przypisuje mu się przetłumaczenie trzech, <a href=\"https://pl.wikipedia.org/wiki/Apokryf\" target=\"_blank\" rel=\"noopener noreferrer\">apokryficznych</a> ksiąg <a href=\"https://pl.wikipedia.org/wiki/Machabeusze\" target=\"_blank\" rel=\"noopener noreferrer\">Machabeuszy</a>. Koriun jako pierwszy podał informację jakoby Mesrop Mesztoc był twórcą <a href=\"https://pl.wikipedia.org/wiki/Alfabet_gruzi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu gruzińskiego</a>. Po śmierci Masztoca Koriun współpracował z Howsepem, jednym z najważniejszych, ormiańskich liderów duchownych. Na jego polecenie zaczął spisywać biografię Mesropa. Zakończył prace jeszcze przed <a href=\"https://pl.wikipedia.org/wiki/Bitwa_pod_Awarajr\" target=\"_blank\" rel=\"noopener noreferrer\">bitwą pod Awarajr</a>, którą datuje się na 451 rok i która doprowadziła do znacznych zmian w regionie. Prace Koriuna zostały przetłumaczone między innymi na <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">rosyjski</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielski</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecki</a>.", "Klodian": "Klodion był na poły legendarnym królem <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">Franków</a> salickich. Uważa się go za ojca <a href=\"https://pl.wikipedia.org/wiki/Meroweusz\" target=\"_blank\" rel=\"noopener noreferrer\">Meroweusza</a> (łac. <i>Merovechus</i> lub <i>Meroveus</i>). Miał być synem <a href=\"https://pl.wikipedia.org/wiki/Faramund\" target=\"_blank\" rel=\"noopener noreferrer\">Faramunda</a> (łac. <i>Pharamundus</i>) i Argotty, pochodzącej z <a href=\"https://pl.wikipedia.org/wiki/Turyngia\" target=\"_blank\" rel=\"noopener noreferrer\">Turyngii</a>. Tym samym był prawdopodobnym następcą <a href=\"https://pl.wikipedia.org/wiki/Markomer\" target=\"_blank\" rel=\"noopener noreferrer\">Markomera</a> (łac. <i>Marcomerus</i> lub <i>Marcomirus</i>), nieznanego bliżej władcy Franków salickich. W czasie panowania rezydował w Tornacum, obecnie <a href=\"https://pl.wikipedia.org/wiki/Tournai\" target=\"_blank\" rel=\"noopener noreferrer\">Tournai</a> w <a href=\"https://pl.wikipedia.org/wiki/Belgia\" target=\"_blank\" rel=\"noopener noreferrer\">Belgii</a>.", "Kazuya": "<b>Kazuya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずや, カズヤ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Klement": "<b>Klemens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „człowiek o łagodnym usposobieniu”, „delikatny”, „pobłażliwy”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Klemencja\" target=\"_blank\" rel=\"noopener noreferrer\">Klemencja</a>.", "Kajmir": "<b>Kanimir</b>, <b>Kanimier</b>, <b>Kajmir</b>, <b>Kalmir</b> — <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów: <i>Kani-</i> w różnych wersjach brzmieniowych (\"gościć, zapraszać\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"ten, u kogo gości pokój\".", "Kody": "<b>Kod</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>codex</i>), spis – ciąg składników sygnału (kombinacji sygnałów elementarnych, np. kropek i kresek, impulsów prądu, symboli) oraz reguła ich przyporządkowania składnikom wiadomości (np. znakom pisma). W niektórych zastosowaniach, głównie przy przesyłaniu informacji podlegających utajnieniu, zwany jest <a href=\"https://pl.wikipedia.org/wiki/Szyfr\" target=\"_blank\" rel=\"noopener noreferrer\">szyfrem</a>. Kody są stosowane m.in. w telegrafii, telefonii, w technice cyfrowej.", "Kochan": "<b>Kochan</b> – imię <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> (a współcześnie polskie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> odimienne), model jednoczłonowy, <a href=\"https://pl.wikipedia.org/wiki/Imies%C5%82%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">imiesłowowy</a> <i>Koch-an</i>, od <i>kochać</i>; zobacz podobne: <a href=\"https://pl.wikipedia.org/wiki/Poznan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Poznan</a>, <a href=\"https://pl.wikipedia.org/wiki/Stojan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Stojan</a>, <a href=\"https://pl.wikipedia.org/wiki/Ciechos%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Ciechan</a>, <a href=\"https://pl.wikipedia.org/wiki/Chocies%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Chocian</a>, mające swoje historyczne i nazewnicze potwierdzenie w licznych nazwach miejscowych: <a href=\"https://pl.wikipedia.org/wiki/Kochan%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Kochanów</a>, <a href=\"https://pl.wikipedia.org/wiki/Kochan%C3%B3wka\" target=\"_blank\" rel=\"noopener noreferrer\">Kochanówka</a>, <a href=\"https://pl.wikipedia.org/wiki/Kochanowo\" target=\"_blank\" rel=\"noopener noreferrer\">Kochanowo</a>. Staropolskie Koch mogło być skróceniem od Kochana, ale również od <a href=\"https://pl.wikipedia.org/wiki/Konstanty\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantyna</a> lub <a href=\"https://pl.wikipedia.org/wiki/Konrad_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Konrada</a>. Imię to notowane w Polsce od 1136 r.", "Krescenty": "<b>Krescenty</b>, <b>Krescencjusz</b>, <b>Krescens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwy rodu, która z kolei pochodzi od słowa <i>crescere</i> – \"wzrastać, narastać\". Wśród patronów – św. Krescencjusz (Krescenty), jeden z synów św. <a href=\"https://pl.wikipedia.org/wiki/Symforoza\" target=\"_blank\" rel=\"noopener noreferrer\">Symforozy</a> (<a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wiek</a>).", "Koppány": "<b>Koppány</b> (zm. <a href=\"https://pl.wikipedia.org/wiki/997\" target=\"_blank\" rel=\"noopener noreferrer\">997</a>) – <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierski</a> książę. Pochodził z dynastii <a href=\"https://pl.wikipedia.org/wiki/Arpadowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arpadów</a>, jednak nie wiadomo z której linii. Przypuszcza się, że był potomkiem <a href=\"https://pl.wikipedia.org/wiki/Tarhos\" target=\"_blank\" rel=\"noopener noreferrer\">Tarhosa</a>. Był synem Zerinda.", "Kagan": "Pierwsze świadectwo odnośnie do używania tytułu kagan pochodzi z ok. 265 roku. Wtedy to w źródłach <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chińskich</a> tytuł pojawia się w związku z Qifu, jednym z plemion <a href=\"https://pl.wikipedia.org/wiki/Xianbei\" target=\"_blank\" rel=\"noopener noreferrer\">Xianbei</a>. Tytuł rozpowszechnił się w związku z używaniem go przez władców <a href=\"https://pl.wikipedia.org/wiki/Rouran\" target=\"_blank\" rel=\"noopener noreferrer\">Rouran</a> oraz ich następców, <a href=\"https://pl.wikipedia.org/wiki/Turkuci\" target=\"_blank\" rel=\"noopener noreferrer\">Turkutów</a>. Następnie używany był przez wielu władców <a href=\"https://pl.wikipedia.org/wiki/Ludy_tureckie\" target=\"_blank\" rel=\"noopener noreferrer\">tureckich</a>, <a href=\"https://pl.wikipedia.org/wiki/Mongo%C5%82owie\" target=\"_blank\" rel=\"noopener noreferrer\">mongolskich</a>, <a href=\"https://pl.wikipedia.org/wiki/Awarowie\" target=\"_blank\" rel=\"noopener noreferrer\">Awarów</a>, a także <a href=\"https://pl.wikipedia.org/wiki/Rusowie\" target=\"_blank\" rel=\"noopener noreferrer\">Rusów</a>, którzy przyjęli go za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/Chazarowie\" target=\"_blank\" rel=\"noopener noreferrer\">Chazarów</a>.", "Kawa": "<b>Kawa</b> – napój sporządzany z palonych, a następnie zmielonych lub poddanych <a href=\"https://pl.wikipedia.org/wiki/Instantyzacja\" target=\"_blank\" rel=\"noopener noreferrer\">instantyzacji</a> ziaren <a href=\"https://pl.wikipedia.org/wiki/Kawowiec\" target=\"_blank\" rel=\"noopener noreferrer\">kawowca</a>, zwykle podawany na gorąco. Pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">Etiopii</a>, w <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a> pojawiła się około XVI wieku. Jedna z najpopularniejszych <a href=\"https://pl.wikipedia.org/wiki/U%C5%BCywka\" target=\"_blank\" rel=\"noopener noreferrer\">używek</a> na świecie i główne źródło <a href=\"https://pl.wikipedia.org/wiki/Kofeina\" target=\"_blank\" rel=\"noopener noreferrer\">kofeiny</a>.", "Katsumi": "<b>Katsumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かつみ, カツミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Kuber": "Informacje o Kuberze pochodzą wyłącznie z <i>Żywota i cudów świętego Demetriusza</i>. Nie są znane okoliczności w jakich w II połowie VII wieku pojawił się na czele koczowników bułgarskich w granicach państwa <a href=\"https://pl.wikipedia.org/wiki/Kaganat_Awar%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">awarskiego</a>. Ponieważ nastąpiło to w okresie po śmierci chana Kubrata i po najeździe <a href=\"https://pl.wikipedia.org/wiki/Chazarowie\" target=\"_blank\" rel=\"noopener noreferrer\">Chazarów</a> na <a href=\"https://pl.wikipedia.org/wiki/Wielka_Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Wielką Bułgarię</a>, jest możliwe, że opuścił Wielką Bułgarię pod naporem Chazarów i przeniósł się ze swym ludem na zachód. Historyk bizantyjski <a href=\"https://pl.wikipedia.org/wiki/Teofan_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Teofanes</a> piszący w IX wieku podaje informację, że synowie Kubrata po śmierci ojca, pokonani przez Chazarów, w większości opuścili ziemie Wielkiej Bułgarii. O czwartym z synów pisze tak: „poddawszy się kaganowi awarskiemu został ze swoim ludem w Panonii awarskiej”. Zdaniem części historyków jest całkiem możliwe, że nieznany z imienia syn Kubrata jest Kuberem, o którym mówi <i>Żywot i cuda św. Demetriusza</i>.", "Karion": "<b>Jądro komórkowe</b>, <b>nukleus</b> – otoczone podwójną błoną <a href=\"https://pl.wikipedia.org/wiki/Organellum\" target=\"_blank\" rel=\"noopener noreferrer\">organellum</a> obecne we wszystkich <a href=\"https://pl.wikipedia.org/wiki/Kom%C3%B3rka\" target=\"_blank\" rel=\"noopener noreferrer\">komórkach</a> <a href=\"https://pl.wikipedia.org/wiki/Eukarionty\" target=\"_blank\" rel=\"noopener noreferrer\">eukariotycznych</a>, z wyjątkiem tych, które wtórnie je utraciły w trakcie różnicowania, np. dojrzałe <a href=\"https://pl.wikipedia.org/wiki/Erytrocyt\" target=\"_blank\" rel=\"noopener noreferrer\">erytrocyty</a> niektórych <a href=\"https://pl.wikipedia.org/wiki/Ssaki\" target=\"_blank\" rel=\"noopener noreferrer\">ssaków</a> (min. człowiek i <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82py_cz%C5%82ekokszta%C5%82tne\" target=\"_blank\" rel=\"noopener noreferrer\">człekokształtne</a>). Zawiera większość <a href=\"https://pl.wikipedia.org/wiki/Materia%C5%82_genetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">materiału genetycznego</a> komórki, zorganizowanego w postaci wielu długich, <a href=\"https://pl.wikipedia.org/wiki/Podw%C3%B3jna_helisa\" target=\"_blank\" rel=\"noopener noreferrer\">dwuniciowych łańcuchów</a> <a href=\"https://pl.wikipedia.org/wiki/Kwas_deoksyrybonukleinowy\" target=\"_blank\" rel=\"noopener noreferrer\">DNA</a> związanych z dużą ilością <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82ka\" target=\"_blank\" rel=\"noopener noreferrer\">białek</a>, głównie <a href=\"https://pl.wikipedia.org/wiki/Histony\" target=\"_blank\" rel=\"noopener noreferrer\">histonowych</a>, które razem tworzą <a href=\"https://pl.wikipedia.org/wiki/Chromosom\" target=\"_blank\" rel=\"noopener noreferrer\">chromosomy</a>. <a href=\"https://pl.wikipedia.org/wiki/Gen\" target=\"_blank\" rel=\"noopener noreferrer\">Geny</a> zlokalizowane w chromosomach stanowią <a href=\"https://pl.wikipedia.org/wiki/Genom\" target=\"_blank\" rel=\"noopener noreferrer\">genom</a> komórki. Funkcją jądra komórkowego jest przechowywanie i <a href=\"https://pl.wikipedia.org/wiki/Replikacja_DNA\" target=\"_blank\" rel=\"noopener noreferrer\">powielanie</a> informacji genetycznej oraz kontrolowanie czynności komórki, poprzez regulowanie <a href=\"https://pl.wikipedia.org/wiki/Ekspresja_genu\" target=\"_blank\" rel=\"noopener noreferrer\">ekspresji genów</a>. Główne struktury, które obecne są w budowie jądra komórkowego to <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ona_j%C4%85drowa\" target=\"_blank\" rel=\"noopener noreferrer\">błona jądrowa</a>, podwójna membrana otaczająca całe organellum i oddzielająca je od <a href=\"https://pl.wikipedia.org/wiki/Cytoplazma\" target=\"_blank\" rel=\"noopener noreferrer\">cytoplazmy</a> oraz blaszka jądrowa, sieć delikatnych włókienek białkowych utworzonych przez <a href=\"https://pl.wikipedia.org/wiki/Laminy\" target=\"_blank\" rel=\"noopener noreferrer\">laminy</a>, stanowiących rusztowanie dla jądra i nadających mu wytrzymałość mechaniczną. Błona jądrowa jest nieprzepuszczalna dla większości cząsteczek, dlatego obecne są w niej <a href=\"https://pl.wikipedia.org/wiki/Por_j%C4%85drowy\" target=\"_blank\" rel=\"noopener noreferrer\">pory jądrowe</a>. Są to kanały przechodzące przez obie błony, umożliwiające transport <a href=\"https://pl.wikipedia.org/wiki/Jon\" target=\"_blank\" rel=\"noopener noreferrer\">jonów</a> i innych cząstek. Transport większych cząstek, takich jak białka, jest ściśle kontrolowany i zachodzi na zasadzie <a href=\"https://pl.wikipedia.org/wiki/Transport_aktywny\" target=\"_blank\" rel=\"noopener noreferrer\">transportu aktywnego</a>, kontrolowanego przez białka transportowe. Transport jądrowy jest kluczowy dla funkcjonowania komórki, ponieważ przemieszczanie cząstek poprzez błonę jądrową wymagane jest zarówno przy zarządzaniu ekspresją genów oraz utrzymywaniu chromosomów.", "Korai": "<b>Kora</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;κόρη <i>kore</i> – dziewczyna; <a href=\"https://pl.wikipedia.org/wiki/Liczba_mnoga\" target=\"_blank\" rel=\"noopener noreferrer\">lm.</a> <i>korai</i>) – w sztuce Grecji <a href=\"https://pl.wikipedia.org/wiki/Okres_archaiczny_(staro%C5%BCytna_Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">okresu archaicznego</a> najstarszy typ greckiego posągu kobiecego, wyobrażający stojącą dziewczynę w długich szatach, często z owocem, kwiatem lub ptakiem w ręku; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Kuros\" target=\"_blank\" rel=\"noopener noreferrer\">kurosa</a>.", "Kornelia": "<b>Kornelia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Kornel</a>, <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusz</a> i <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Korneli</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliuszy</a>. Imię to było znane już w starożytności. W Polsce nadawane co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1770\" target=\"_blank\" rel=\"noopener noreferrer\">1770</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Kornelia w 2017 r. zajmowała 25. miejsce w grupie imion żeńskich.", "Kalasanty": "<b>Kalasanty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie powstałe od nazwy miejscowości (Calasanza) w Hiszpanii. Pierwotnie był to jedynie drugi człon nazywający świętego z przełomu XVI i XVII wieku, <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Kalasancjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Józefa Kalasantego</a> (<i>José de Calasanza</i>), założyciela zakonu pijarów.", "Kira": "<b>Cyra</b>, <i>Kira</i> – żeński odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Cyrus\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrus</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Marana_i_Cyra\" target=\"_blank\" rel=\"noopener noreferrer\">św. Cyra</a> z V wieku.", "Kalmir": "<b>Kanimir</b>, <b>Kanimier</b>, <b>Kajmir</b>, <b>Kalmir</b> — <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów: <i>Kani-</i> w różnych wersjach brzmieniowych (\"gościć, zapraszać\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"ten, u kogo gości pokój\".", "Kazuyuki": "<b>Kazuyuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずゆき, カズユキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Kiwa": "<b>Kiwaidae</b> – <a href=\"https://pl.wikipedia.org/wiki/Rodzina_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzina</a> <a href=\"https://pl.wikipedia.org/wiki/Skorupiaki\" target=\"_blank\" rel=\"noopener noreferrer\">skorupiaków</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Dziesi%C4%99cionogi\" target=\"_blank\" rel=\"noopener noreferrer\">dziesięcionogów</a> (Decapoda). Występują na dużych głębokościach, w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Komin_hydrotermalny\" target=\"_blank\" rel=\"noopener noreferrer\">kominów hydrotermalnych</a>. Rodzina obejmuje <a href=\"https://pl.wikipedia.org/wiki/Takson_monotypowy\" target=\"_blank\" rel=\"noopener noreferrer\">jeden</a> rodzaj – <i>Kiwa</i>. Należą do niego cztery gatunki, z których dwa zostały formalnie opisane: <a href=\"https://pl.wikipedia.org/wiki/Gatunek_typowy\" target=\"_blank\" rel=\"noopener noreferrer\">typowy</a> <i><a href=\"https://pl.wikipedia.org/wiki/Kiwa_hirsuta\" target=\"_blank\" rel=\"noopener noreferrer\">Kiwa hirsuta</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Kiwa_puravida\" target=\"_blank\" rel=\"noopener noreferrer\">Kiwa puravida</a></i>. Rodzina została nazwana w 2005 roku przez Enrique Macphersona i współpracowników jako monotypowa rodzina dla <i>K. hirsuta</i>. <i>K. puravida</i> opisano w 2011 roku. Trzeci gatunek żyje w pobliżu kominów hydrotermalnych na East Scotia Ridge na <a href=\"https://pl.wikipedia.org/wiki/Ocean_Po%C5%82udniowy\" target=\"_blank\" rel=\"noopener noreferrer\">Oceanie Południowym</a>, a czwarty – na Southwest Indian Ridge.", "Kamila": "<b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Karolina": "<b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Keigo": "<b>Keigo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;敬語) – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> język zwrotów grzecznościowych. W językach europejskich istnieje mniej poziomów formalności, zwykle jeden jak w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a> lub też dwa jak w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a> czy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a>. Mają one też mniejszy wpływ na gramatykę – dotyczą głównie zdań dotyczących współrozmówcy, nie zaś siebie samego czy przedmiotów i osób trzecich.", "Kodi": "Pozwala uruchamiać aplikacje oficjalne i tworzone przez konsumentów tzw. homebrew oraz oglądać filmy, słuchać muzyki i przeglądać cyfrowe zdjęcia bezpośrednio z wbudowanego w <a href=\"https://pl.wikipedia.org/wiki/Xbox\" target=\"_blank\" rel=\"noopener noreferrer\">Xboksa</a> <a href=\"https://pl.wikipedia.org/wiki/Dysk_twardy\" target=\"_blank\" rel=\"noopener noreferrer\">dysku twardego</a>, czytnika <a href=\"https://pl.wikipedia.org/wiki/DVD\" target=\"_blank\" rel=\"noopener noreferrer\">DVD</a>, lokalnej sieci komputerowej, <a href=\"https://pl.wikipedia.org/wiki/Internet\" target=\"_blank\" rel=\"noopener noreferrer\">Internetu</a> lub z nośnika danych podłączonego przez przejściówkę pod port USB (np. z pendrive’a, jeżeli jest kompatybilny). Po podłączeniu konsoli do Internetu dodatkowo można sprawdzić pogodę, posłuchać radia internetowego, pograć w gry online w systemie xLink lub pobrać informację na temat oglądanego filmu. Dzięki instalacji dodatkowych <a href=\"https://pl.wikipedia.org/wiki/Wtyczka\" target=\"_blank\" rel=\"noopener noreferrer\">wtyczek</a> (skryptów) do programu można dodać dodatkowe funkcje, na przykład skrzynkę <a href=\"https://pl.wikipedia.org/wiki/Poczta_elektroniczna\" target=\"_blank\" rel=\"noopener noreferrer\">e-mail</a>, program TV, <a href=\"https://pl.wikipedia.org/wiki/Telewizja_internetowa\" target=\"_blank\" rel=\"noopener noreferrer\">telewizje internetową</a>, <a href=\"https://pl.wikipedia.org/wiki/Przegl%C4%85darka_internetowa\" target=\"_blank\" rel=\"noopener noreferrer\">przeglądarkę WWW</a> i wiele innych.", "Kaja": "<b>Gaja</b>, <b>Kaja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/Gaja_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">postaci z mitologii greckiej</a>, Ziemi-Matki (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Γαῖα – „Ziemia”), lub stanowiące żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a> (<i>Gaius</i>), należącego do nielicznej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>). Według różnych źródeł Gajusz ma bądź to niewyjaśnione pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckie</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskie</a>, bądź to uznawane jest za oznaczające „cieszący (rodziców)”, por. <i>gaudeo</i> – „cieszę się” (zob. <a href=\"https://pl.wikipedia.org/wiki/Gaudenty_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gaudenty</a>). Gaja oznaczałaby zatem „ciesząca rodziców”.", "Karno": "<b>Karno</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>Carneau</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rasy_go%C5%82%C4%99bia\" target=\"_blank\" rel=\"noopener noreferrer\">rasa gołębia</a> należąca do grupy uformowanych (<a href=\"https://pl.wikipedia.org/wiki/Rasy_go%C5%82%C4%99bia#Grupa_I_–_uformowane\" target=\"_blank\" rel=\"noopener noreferrer\">grupa I</a>), pochodzących (jak wszystkie inne) od <a href=\"https://pl.wikipedia.org/wiki/Domestykacja_zwierz%C4%85t\" target=\"_blank\" rel=\"noopener noreferrer\">udomowionego</a> <a href=\"https://pl.wikipedia.org/wiki/Go%C5%82%C4%85b_skalny\" target=\"_blank\" rel=\"noopener noreferrer\">gołębia skalnego</a>. Rasa wywodzi się z północnej <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a> i południowej <a href=\"https://pl.wikipedia.org/wiki/Belgia\" target=\"_blank\" rel=\"noopener noreferrer\">Belgii</a>, gdzie została <a href=\"https://pl.wikipedia.org/wiki/Hodowla\" target=\"_blank\" rel=\"noopener noreferrer\">wyhodowana</a> około IX wieku, a opisana w 1891 roku. Istnieją dwa typy rasy: europejski oraz amerykański. Karno jest gołębiem użytkowym, nierzadko wystawowym, a amerykański typ rasy jest przeznaczony do konsumpcji (z uwagi na dużą wagę i odporność reprodukcja jest wydajna).", "Kyrie": "Forma wołania błagalnego występująca w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> (Ps. 40, 5; 40, 11, Iz. 33,2, a w zmienionej postaci <i>eleison me kyrie</i> - Ps. 7, 3; 10, 14; 31, 10; 56, 2; 86, 3 – numeracja według <a href=\"https://pl.wikipedia.org/wiki/Septuaginta\" target=\"_blank\" rel=\"noopener noreferrer\">Septuaginty</a>), która w tej postaci została przejęta do wszystkich liturgii Kościoła katolickiego.", "K": "<b>K</b> (<a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>k</b>) (<i>ka</i>) – jedenasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i czternasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. W języku polskim oznacza <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę zwartą miękkopodniebienną bezdźwięczną</a>. Pochodzi od litery <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu fenickiego</a> <a href=\"https://pl.wikipedia.org/wiki/Kaf\" target=\"_blank\" rel=\"noopener noreferrer\">kaph</a>, za pośrednictwem litery alfabetu greckiego <a href=\"https://pl.wikipedia.org/wiki/Kappa_(litera)\" target=\"_blank\" rel=\"noopener noreferrer\">kappa</a> i alfabetu etruskiego.", "Kunihiko": "<b>Kunihiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;くにひこ, クニヒコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Kanji": "<b>Kanji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;漢字&#32;<i>kanji</i>&#59; „znaki <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Han\" target=\"_blank\" rel=\"noopener noreferrer\">Hanów</a>”) – <a href=\"https://pl.wikipedia.org/wiki/Pismo_logograficzne\" target=\"_blank\" rel=\"noopener noreferrer\">znaki logograficzne</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chińskiego</a>, które wraz z <a href=\"https://pl.wikipedia.org/wiki/Sylabariusz\" target=\"_blank\" rel=\"noopener noreferrer\">sylabariuszami</a> <a href=\"https://pl.wikipedia.org/wiki/Hiragana\" target=\"_blank\" rel=\"noopener noreferrer\">hiragana</a> (ひらがな, 平仮名), <a href=\"https://pl.wikipedia.org/wiki/Katakana\" target=\"_blank\" rel=\"noopener noreferrer\">katakana</a> (カタカナ, 片仮名), <a href=\"https://pl.wikipedia.org/wiki/Cyfry_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">cyframi arabskimi</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetem łacińskim</a> stanowią element <a href=\"https://pl.wikipedia.org/wiki/Pismo_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">pisma japońskiego</a>.", "Karmel": "Jest głównym składnikiem niektórych rodzajów <a href=\"https://pl.wikipedia.org/wiki/Cukierek\" target=\"_blank\" rel=\"noopener noreferrer\">cukierków</a>, <a href=\"https://pl.wikipedia.org/wiki/Barwniki_spo%C5%BCywcze\" target=\"_blank\" rel=\"noopener noreferrer\">barwnikiem</a> napojów typu <a href=\"https://pl.wikipedia.org/wiki/Cola\" target=\"_blank\" rel=\"noopener noreferrer\">cola</a>, ciemnego <a href=\"https://pl.wikipedia.org/wiki/Pieczywo\" target=\"_blank\" rel=\"noopener noreferrer\">pieczywa</a>, <a href=\"https://pl.wikipedia.org/wiki/Czekolada\" target=\"_blank\" rel=\"noopener noreferrer\">czekolad</a>, <a href=\"https://pl.wikipedia.org/wiki/Lody\" target=\"_blank\" rel=\"noopener noreferrer\">lodów</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCem\" target=\"_blank\" rel=\"noopener noreferrer\">dżemów</a> i <a href=\"https://pl.wikipedia.org/wiki/Jogurt\" target=\"_blank\" rel=\"noopener noreferrer\">jogurtów</a>. Dodatek karmelu do żywności jest oznaczany przez kod E150 i literę wyróżniającą typ karmelu.", "Kamillus": "<b>Marek Furiusz Kamillus</b>, <i>Marcus Furius Camillus</i> (ur. około <a href=\"https://pl.wikipedia.org/wiki/446_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">446 p.n.e.</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/364_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">364 p.n.e.</a>) – wódz i reformator armii <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiej</a>, wielokrotny <a href=\"https://pl.wikipedia.org/wiki/Konsul_rzymski#Republika\" target=\"_blank\" rel=\"noopener noreferrer\">trybun konsularny</a> i <a href=\"https://pl.wikipedia.org/wiki/Dyktator_(staro%C5%BCytny_Rzym)\" target=\"_blank\" rel=\"noopener noreferrer\">dyktator</a>.", "Kaname": "<b>Kaname</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かなめ, カナメ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Kirtan": "Praktykowanie <i>sankirtanu</i> rozpoczął święty i reformator <a href=\"https://pl.wikipedia.org/wiki/Gaudija_wisznuizm\" target=\"_blank\" rel=\"noopener noreferrer\">gaudija wisznuizmu</a> – <a href=\"https://pl.wikipedia.org/wiki/%C4%86ajtanja_Mahaprabhu\" target=\"_blank\" rel=\"noopener noreferrer\">Ćajtanja Mahaprabhu</a> w <a href=\"https://pl.wikipedia.org/wiki/XVI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVI wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Bengal\" target=\"_blank\" rel=\"noopener noreferrer\">Bengalu</a> (<a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indie</a> wschodnie). Współcześnie <i>sankirtan</i> jest propagowany na całym świecie przez <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowe_Towarzystwo_%C5%9Awiadomo%C5%9Bci_Kryszny\" target=\"_blank\" rel=\"noopener noreferrer\">Międzynarodowe Towarzystwo Świadomości Kryszny</a> (ISKCON) i inne ruchy religijne wywodzące się z gaudija wisznuizmu. W ISKCON słowo <i>sankirtan</i> oznacza także rozpowszechnianie pism i książek lub wszelkiego rodzaju propagowanie religii.", "Kryspinian": "<b>Kryspinian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od imienia <a href=\"https://pl.wikipedia.org/wiki/Kryspin\" target=\"_blank\" rel=\"noopener noreferrer\">Kryspin</a> (od łac. <i>crispus</i>, 'kędzierzawy'). Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Kryspin_i_Kryspinian\" target=\"_blank\" rel=\"noopener noreferrer\">św. Kryspinian</a>, wspominany razem ze <a href=\"https://pl.wikipedia.org/wiki/Kryspin_i_Kryspinian\" target=\"_blank\" rel=\"noopener noreferrer\">św. Kryspinem</a>.", "Kadi": "Od nazwy tej pochodzi <a href=\"https://pl.wikipedia.org/wiki/Alkad\" target=\"_blank\" rel=\"noopener noreferrer\">alkad</a>.", "Kalev": "<b>Kalev</b> – według mitologii fińskiej praojciec wszystkich <a href=\"https://pl.wikipedia.org/wiki/Finowie\" target=\"_blank\" rel=\"noopener noreferrer\">Finów</a>, bardzo ważna postać dla <a href=\"https://pl.wikipedia.org/wiki/Finowie\" target=\"_blank\" rel=\"noopener noreferrer\">Finów</a>, <a href=\"https://pl.wikipedia.org/wiki/Esto%C5%84czycy\" target=\"_blank\" rel=\"noopener noreferrer\">Estończyków</a> i <a href=\"https://pl.wikipedia.org/wiki/Karelowie\" target=\"_blank\" rel=\"noopener noreferrer\">Karelów</a> i innych narodów bałtycko-fińskich. Występował w <a href=\"https://pl.wikipedia.org/wiki/Finlandia\" target=\"_blank\" rel=\"noopener noreferrer\">fińskiej</a> \"<a href=\"https://pl.wikipedia.org/wiki/Kalevala\" target=\"_blank\" rel=\"noopener noreferrer\">Kalevali</a>\" i w <a href=\"https://pl.wikipedia.org/wiki/Estonia\" target=\"_blank\" rel=\"noopener noreferrer\">estońskim</a> \"Kalevipoeg\" (Synowie Kaleva). W sagach <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskich</a> występuje jako <b>Fornjotr</b> i według legendy pochodził z terenów <a href=\"https://pl.wikipedia.org/wiki/Estonia\" target=\"_blank\" rel=\"noopener noreferrer\">Estonii</a>, a następnie przeniósł się do <a href=\"https://pl.wikipedia.org/wiki/Finlandia\" target=\"_blank\" rel=\"noopener noreferrer\">Finlandii</a>. Zjednoczył wszystkie fińskie plemiona, miał żyć w latach ok. 160-210. Do dziś w języku estońskim pojęcie Kalev jest kojarzone z nadludzką siłą i potęgą, które były atrybutami tego herosa.", "Kip": "W 1979 roku nastąpiła w Laosie reforma walutowa. 100 starych kipów zastąpiono 1 nowym. Notowania (na dzień <a href=\"https://pl.wikipedia.org/wiki/Stycze%C5%84_2014#5_stycznia_2014\" target=\"_blank\" rel=\"noopener noreferrer\">5 stycznia 2014</a>): 1 USD = 8035 LAK, 1 PLN = 2619 LAK.", "Kalistrat": "<b>Kalistrat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się ze złożenia słów <i>kalios</i> i <i>stratos</i> oznaczających kolejno \"piękno\" i \"armia\". Imię to nosiło kilku świętych katolickich.", "Klet": "<b>Klet</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o niejasnej etymologii. Może być ono użytym jako nazwa własna <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> przymiotnikiem <i>kl-tós</i> oznaczającym: \"wybrany\", \"wezwany\", jak również może być aluzją do greckiego ewangelicznego cytatu: \"<i>polloi eisi kl-toi, olígoi d- eklektoi\" -</i> \"wielu wezwanych, mało wybranych\".", "Kociemir": "<b>Chociemir</b>, <b>Chocimier</b>, <b>Chocimir</b>, <b>Chocimirz</b>, <b>Kociemir</b>, <b>Kociemiar</b>, <b>Kociemier</b>, <b>Kocimiar</b>, <b>Kocimier</b>, <b>Kocimir</b>, <b>Koćmir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Chocie-</i> („chcieć”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „pragnący pokoju”.", "Kalwin": "<b>Jan Kalwin</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>&#160;<em>Jean Cauvin</em> albo również <i>Jean Calvin</i>; ur. <a href=\"https://pl.wikipedia.org/wiki/10_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">10 lipca</a> <a href=\"https://pl.wikipedia.org/wiki/1509\" target=\"_blank\" rel=\"noopener noreferrer\">1509</a> w <a href=\"https://pl.wikipedia.org/wiki/Noyon\" target=\"_blank\" rel=\"noopener noreferrer\">Noyon</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/27_maja\" target=\"_blank\" rel=\"noopener noreferrer\">27 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1564\" target=\"_blank\" rel=\"noopener noreferrer\">1564</a> w <a href=\"https://pl.wikipedia.org/wiki/Genewa\" target=\"_blank\" rel=\"noopener noreferrer\">Genewie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Francuzi\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a> <a href=\"https://pl.wikipedia.org/wiki/Teolog\" target=\"_blank\" rel=\"noopener noreferrer\">teolog</a> protestancki, reformator, <a href=\"https://pl.wikipedia.org/wiki/Kaznodzieja\" target=\"_blank\" rel=\"noopener noreferrer\">kaznodzieja</a>, <a href=\"https://pl.wikipedia.org/wiki/Humanista\" target=\"_blank\" rel=\"noopener noreferrer\">humanista</a>, <a href=\"https://pl.wikipedia.org/wiki/Pisarz\" target=\"_blank\" rel=\"noopener noreferrer\">pisarz</a> i organizator życia duchowego w <a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">Szwajcarii</a> w okresie <a href=\"https://pl.wikipedia.org/wiki/Reformacja\" target=\"_blank\" rel=\"noopener noreferrer\">reformacji</a>. Twórca jednej z doktryn religijnych – <a href=\"https://pl.wikipedia.org/wiki/Kalwinizm\" target=\"_blank\" rel=\"noopener noreferrer\">ewangelicyzmu reformowanego</a> (od jego nazwiska nazywanej kalwinizmem), przyjętej przez <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bcio%C5%82y_ewangelicko-reformowane\" target=\"_blank\" rel=\"noopener noreferrer\">Kościoły ewangelicko-reformowane</a>, <a href=\"https://pl.wikipedia.org/wiki/Prezbiterianizm\" target=\"_blank\" rel=\"noopener noreferrer\">prezbiteriańskie</a>, a następnie przez część <a href=\"https://pl.wikipedia.org/wiki/Kongregacjonalizm\" target=\"_blank\" rel=\"noopener noreferrer\">kongregacjonalnych</a>, opierającej się głównie na nauce o <a href=\"https://pl.wikipedia.org/wiki/Predestynacja\" target=\"_blank\" rel=\"noopener noreferrer\">predestynacji</a> oraz nauce o realnej i duchowej obecności <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a> w <a href=\"https://pl.wikipedia.org/wiki/Eucharystia_(sakrament)\" target=\"_blank\" rel=\"noopener noreferrer\">Wieczerzy Pańskiej</a>, w odróżnieniu od poglądu powszechnie panującego w <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościele katolickim</a> (obecności realnej i cielesnej). Nazywany przez swych zwolenników „teologiem <a href=\"https://pl.wikipedia.org/wiki/Par_excellence\" target=\"_blank\" rel=\"noopener noreferrer\">par excellence</a>”; „Arystotelesem Reformacji”; „Akwinatą Kościoła reformowanego”; „najbardziej chrześcijańskim mężem swej epoki” czy też „drugim patriarchą reformacji”.", "Key": "<b>Key</b> – japońskie studio tworzące <a href=\"https://pl.wikipedia.org/wiki/Powie%C5%9B%C4%87_wizualna\" target=\"_blank\" rel=\"noopener noreferrer\">powieści wizualne</a>, będące formalnie marką wydawcy gier komputerowych <a href=\"https://pl.wikipedia.org/wiki/Visual_Arts\" target=\"_blank\" rel=\"noopener noreferrer\">Visual Arts</a>. Jest jednym z głównych przedstawicieli nurtu <i>nakige</i>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;泣きゲ&#59; „gry wywołujące łzy”). Pierwszym tytułem studia była wydana w 1999 roku <a href=\"https://pl.wikipedia.org/wiki/Eroge\" target=\"_blank\" rel=\"noopener noreferrer\">gra dla dorosłych</a> <i><a href=\"https://pl.wikipedia.org/wiki/Kanon_(gra_komputerowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Kanon</a></i>. W 2004 roku wydana została pierwsza produkcja studia przeznaczona dla wszystkich grup wiekowych – <i><a href=\"https://pl.wikipedia.org/wiki/Clannad_(gra_komputerowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Clannad</a></i>. Key współpracowało ze studiem animacyjnym <a href=\"https://pl.wikipedia.org/wiki/P.A._Works\" target=\"_blank\" rel=\"noopener noreferrer\">P.A. Works</a> oraz firmą <a href=\"https://pl.wikipedia.org/wiki/Aniplex\" target=\"_blank\" rel=\"noopener noreferrer\">Aniplex</a> przy produkcji seriali <a href=\"https://pl.wikipedia.org/wiki/Anime\" target=\"_blank\" rel=\"noopener noreferrer\">anime</a> <i><a href=\"https://pl.wikipedia.org/wiki/Angel_Beats!\" target=\"_blank\" rel=\"noopener noreferrer\">Angel Beats!</a></i> (2010), <i><a href=\"https://pl.wikipedia.org/wiki/Charlotte_(anime)\" target=\"_blank\" rel=\"noopener noreferrer\">Charlotte</a></i> (2015) i <i><a href=\"https://pl.wikipedia.org/wiki/Kami-sama_ni_natta_hi\" target=\"_blank\" rel=\"noopener noreferrer\">Kami-sama ni natta hi</a></i> (2020).", "Kido": "Dnia 13 lutego 2009 roku firma <a href=\"https://pl.wikipedia.org/wiki/Microsoft\" target=\"_blank\" rel=\"noopener noreferrer\">Microsoft</a> wyznaczyła po 250 tys. <a href=\"https://pl.wikipedia.org/wiki/Dolar_ameryka%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">dolarów</a> nagrody dla każdego, kto jest w stanie udzielić informacji mogących pomóc w ujęciu twórcy <a href=\"https://pl.wikipedia.org/wiki/Wirus_komputerowy\" target=\"_blank\" rel=\"noopener noreferrer\">wirusa</a>.", "Kier": "Odpowiednikiem kierów w talii niemieckiej są serca, w talii szwajcarskiej – kwiaty, zaś w talii włosko-hiszpańskiej puchary.", "Kerr": "<b>Kerr</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gaelicki_szkocki\" target=\"_blank\" rel=\"noopener noreferrer\">gael.</a> <i>Cearr</i>, <i>MacGhillechearr</i>) – szkockie nazwisko i nazwa klanu ze szkockich <a href=\"https://pl.wikipedia.org/wiki/Lowlands\" target=\"_blank\" rel=\"noopener noreferrer\">Nizin</a> i <a href=\"https://pl.wikipedia.org/wiki/Borders\" target=\"_blank\" rel=\"noopener noreferrer\">Pogranicza</a>. Klan pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Normanowie\" target=\"_blank\" rel=\"noopener noreferrer\">normańskiego</a>. pochodzenie nazwiska, pisanego dawniej jako <b>Carr</b>, <b>Ker</b> lub <b>Carre</b>, nie jest do końca wyjaśnione. Istniejące hipotezy wywodzą je od:", "Karunesh": "Po poważnym wypadku drogowym wyjechał w 1979 do <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indii</a>, gdzie poznał <a href=\"https://pl.wikipedia.org/wiki/Osho_(guru)\" target=\"_blank\" rel=\"noopener noreferrer\">Osho</a>, przeszedł inicjację w <a href=\"https://pl.wikipedia.org/wiki/Ashram\" target=\"_blank\" rel=\"noopener noreferrer\">aszramie</a> w <a href=\"https://pl.wikipedia.org/wiki/Pune\" target=\"_blank\" rel=\"noopener noreferrer\">Punie</a> i przyjął imię „<i>Karunesh</i>”, co w <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrycie</a> znaczy „współczucie”. Po powrocie do Niemiec przez pięć lat mieszkał w <a href=\"https://pl.wikipedia.org/wiki/Hamburg\" target=\"_blank\" rel=\"noopener noreferrer\">Hamburgu</a> we wspólnocie <i>Rajneesh</i>, gdzie stykał się z muzykami z całego świata. W <a href=\"https://pl.wikipedia.org/wiki/1987\" target=\"_blank\" rel=\"noopener noreferrer\">1987</a> wydał pierwszy album <i>Sounds of The Heart</i> („Dźwięki serca”), zaliczony do klasyki gatunku. Każdy następny album odnosił spory międzynarodowy sukces.", "Keiji": "<b>Keiji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けいじ, ケイジ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kanimir": "<b>Kanimir</b>, <b>Kanimier</b>, <b>Kajmir</b>, <b>Kalmir</b> — <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów: <i>Kani-</i> w różnych wersjach brzmieniowych (\"gościć, zapraszać\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"ten, u kogo gości pokój\".", "Katarzyna": "<b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Krystyna": "<b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kinga": "<b>Kinga</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia węgierskiego, wywodzące się od zdrobnienia <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kunegunda\" target=\"_blank\" rel=\"noopener noreferrer\">Kunegunda</a>. W piśmiennictwie węgierskim występują formy: <i>Kunegund, Kinga, Kynga, Kynka,</i> natomiast w polskim – <i>Kinga</i> (1278) i <i>Kinka</i> (1320–1329).", "Klaudia": "<b>Klaudia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Claudia</em>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Wywodzi się od nazwy rzymskiego rodu Klaudiuszów. Imię <a href=\"https://pl.wikipedia.org/wiki/Klaudia_(z_Klaudiusz%C3%B3w)\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudia</a> nosiły wszystkie kobiety z tego rodu. Odnotowano trzy święte katolickie o tym imieniu. Istnieje też pochodna forma tego imienia: <a href=\"https://pl.wikipedia.org/wiki/Klaudyna\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudyna</a>.", "Kazimiera": "<b>Kazimiera</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kazimierz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kazimierz</a>. W średniowieczu nie występowało. Prawdopodobnie rozpowszechniło się pod koniec XVII wieku, po przyjeździe do Polski <a href=\"https://pl.wikipedia.org/wiki/Maria_Kazimiera_d%E2%80%99Arquien\" target=\"_blank\" rel=\"noopener noreferrer\">Marysieńki</a>, żony króla <a href=\"https://pl.wikipedia.org/wiki/Jan_III_Sobieski\" target=\"_blank\" rel=\"noopener noreferrer\">Jana III Sobieskiego</a>.", "Klara": "<b>Klara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <i>clarus</i> oznaczającego „jasny”, „jaśniejący”, „sławny”.", "Karina": "<b>Karina</b>, <b>Karyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z jęz. niemieckiego; forma zdrobniała od imienia <i>Katarina</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>). Inna hipoteza mówi, że wywodzi się od słowa <i>cara</i>, które po <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinie</a> oznacza \"kochana, droga\" lub w galickim \"przyjaciel\". Jeszcze inna hipoteza mówi, że pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">konstelacji</a> <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Kila\" target=\"_blank\" rel=\"noopener noreferrer\">Kil</a>, nazwanej w związku kilem statku <a href=\"https://pl.wikipedia.org/wiki/Jazon_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jazona</a>.", "Kalina": "<b>Kalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, stanowiące być może przekształcone na gruncie białoruskim imię <a href=\"https://pl.wikipedia.org/wiki/Akwilina\" target=\"_blank\" rel=\"noopener noreferrer\">Akwilina</a>, lub powstałe na gruncie wschodniosłowiańskim pod wpływem wyrazu <a href=\"https://pl.wikipedia.org/wiki/Kalina_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kalina</a>. Zgodnie z rosyjskimi źródłami, <i><b>Kalinka</b></i> to zdrobnienie zarówno męskie od <a href=\"https://pl.wikipedia.org/wiki/Kalinik\" target=\"_blank\" rel=\"noopener noreferrer\">Kalinika</a>, jak i żeńskie – od żeńskiego rosyjskiego odpowiednika tego imienia, tj. <i>Kallinikii</i> (<i>Каллиникня</i>). Należy też podkreślić, iż forma Kalina spotykana była jako męska forma skrócona imienia <a href=\"https://pl.wikipedia.org/wiki/Kalinik\" target=\"_blank\" rel=\"noopener noreferrer\">Kalinik</a> już w źródłach pochodzących z lat <a href=\"https://pl.wikipedia.org/wiki/1479\" target=\"_blank\" rel=\"noopener noreferrer\">1479</a>–<a href=\"https://pl.wikipedia.org/wiki/1584\" target=\"_blank\" rel=\"noopener noreferrer\">1584</a> z <a href=\"https://pl.wikipedia.org/wiki/Monastyr_So%C5%82owiecki\" target=\"_blank\" rel=\"noopener noreferrer\">monastyru sołowieckiego</a>.", "Karyna": "<b>Karina</b>, <b>Karyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z jęz. niemieckiego; forma zdrobniała od imienia <i>Katarina</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>). Inna hipoteza mówi, że wywodzi się od słowa <i>cara</i>, które po <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinie</a> oznacza \"kochana, droga\" lub w galickim \"przyjaciel\". Jeszcze inna hipoteza mówi, że pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">konstelacji</a> <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Kila\" target=\"_blank\" rel=\"noopener noreferrer\">Kil</a>, nazwanej w związku kilem statku <a href=\"https://pl.wikipedia.org/wiki/Jazon_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jazona</a>.", "Konstancja": "<b>Konstancja</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Konstancjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Konstancjusz</a>, wywodząca się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>constantia</em> – „stałość, stateczność, wytrwałość”.", "Kamilla": "<b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Ksenia": "<b>Ksenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „gościnna” (Ξενία, dosł. „życzliwa dla obcych”), popularne zwłaszcza w krajach prawosławnych: rosyjskie <b>Ксения</b> (<i><b>Ksienija</b></i>), <b>Аксиния</b> (<i><b>Aksinija</b></i>), ukraińskie <b>Ксенія</b> (<i><b>Ksenija</b></i>), <b>Ксеня</b> (<i><b>Ksenia</b></i>) oraz pochodne <b>Оксана</b> (<i><b>Oksana</b></i>), białoruskie <b>Ксенія</b> (<i><b>Ksenìâ</b></i>), czeskie <b>Xenie</b>, słowackie <b>Xeni</b>.", "Krzysztofa": "<b>Krzysztofa</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Krzysztof\" target=\"_blank\" rel=\"noopener noreferrer\">Krzysztof</a> o pochodzeniu greckim.", "Klementyna": "<b>Klementyna</b> – żeński odpowiednik łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Klementyn\" target=\"_blank\" rel=\"noopener noreferrer\">Klementyn</a>.", "Klaudyna": "<b>Klaudyna</b> – pochodna forma imienia <a href=\"https://pl.wikipedia.org/wiki/Klaudia\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudia</a>, powstała od zdrobniałego imienia <i>Claudine</i>, co oznacza 'należąca do rodu Claudia, córka Claudiusa' lub 'mała, kochana Claudia'. Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Klaudyna_Th%C3%A9venet\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudyna Thévenet</a>.", "Kunegunda": "<b>Kunegunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>kuni</i> „(ktoś) ze szlachetnego rodu” oraz <i>gund</i> „walka”, można określić jego pierwotne znaczenie jako „walcząca dla swojego rodu”. Jego zdrobnieniem powstałym na gruncie węgierskim jest <a href=\"https://pl.wikipedia.org/wiki/Kinga\" target=\"_blank\" rel=\"noopener noreferrer\">Kinga</a>, stąd polskie Kinga.", "Kasandra": "<b>Kasandra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, powstałe z wyrazów <i>kekasmai</i> – „wyróżniająca się” i <i>anēr</i>, d. <i>andrós</i> – „człowiek”.", "Ksymena": "<b>Ksymena</b>, <b>Xymena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymon</a>, ukształtowany za pośrednictwem dawnego języka hiszpańskiego.", "Karola": "<b>Karola</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>.", "Kesja": "<b>Kasja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od łacińskiej nazwy rodu Kasjuszy (<i>Cassius</i>). Wśród patronów – czterech świętych.", "Ksawera": "<b>Ksawera</b>, <b>Ksaweryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">Ksawery</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Franciszka_Ksawera\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszka Ksawera</a> Cabrini.", "Krystiana": "<b>Krystiana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Krystian\" target=\"_blank\" rel=\"noopener noreferrer\">Krystian</a>, które powstało poprzez dodanie przyrostka <i>-ianus</i>, oznaczającego przynależność lub pochodzenie, do łacińskiego imienia <i><a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Christinus/Cristinus</a></i>. Oznacza „chrześcijanka, należąca do Chrystusa, Chrystusowa”. Imię to jest poświadczone w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, w formie <i><b>Krzys(z)tyjana</b></i>, <i><b>Krystyjana</b></i>. Staropolskie formy pochodne: Krczona, Krzczona, Chryścijanica, Chrzczonka.", "Kasia": "<b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Kamelia": "<b>Kamelia</b> – imię żeńskie pochodzące od nazwy <a href=\"https://pl.wikipedia.org/wiki/Kamelia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kwitnącego krzewu</a> nazwanego na cześć botanika i misjonarza <a href=\"https://pl.wikipedia.org/wiki/Georg_Joseph_Kamel\" target=\"_blank\" rel=\"noopener noreferrer\">Georga Josepha Kamela</a>.", "Kryspina": "<b>Kryspina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>crispa</i> – (osoba) o kręconych włosach, kędzierzawa.", "Kora": "<b>Kora</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>cortex</em>) – w <a href=\"https://pl.wikipedia.org/wiki/Botanika\" target=\"_blank\" rel=\"noopener noreferrer\">botanice</a> nieprecyzyjna nazwa tkanek w zewnętrznych partiach <a href=\"https://pl.wikipedia.org/wiki/Korze%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">korzenia</a> lub <a href=\"https://pl.wikipedia.org/wiki/%C5%81odyga\" target=\"_blank\" rel=\"noopener noreferrer\">łodygi</a>, może być używana w różnym znaczeniu:", "Kasjana": "<b>Kasjana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kasjan\" target=\"_blank\" rel=\"noopener noreferrer\">Kasjan</a> o pochodzeniu łacińskim.", "Kama": "<b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Koryna": "<b>Koryna</b>, Korynna – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, będące zdrobnieniem imienia <a href=\"https://pl.wikipedia.org/wiki/Kora_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kora</a>, wywodzącego się od słowa <i>kóre</i> „dziewczę”. Patronką tego imienia jest św. Koryna z <a href=\"https://pl.wikipedia.org/wiki/Syria\" target=\"_blank\" rel=\"noopener noreferrer\">Syrii</a> (II wiek).", "Konstantyna": "<b>Konstantyna</b> – imię żeńskie. forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Konstanty\" target=\"_blank\" rel=\"noopener noreferrer\">Konstanty</a>, <a href=\"https://pl.wikipedia.org/wiki/Konstanty\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantyn</a>.", "Kordula": "<b>Kordula</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Cordulus/ula</i>, stanowiącego złożenie wyrazów <i>cor</i>, <i>cordis</i> („serce”) i <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> zdrabniającego <i>-ula</i>. Według innych hipotez pochodzi bezpośrednio od łacińskiego wyrazu <i>cordulum</i> („serduszko”), może stanowić żeńską formę imienia rzymskiego <i>Cordus</i> i oznaczać „późno urodzona” lub pochodzić od nazwy greckiego miasta Kordule. W Polsce notowane od <a href=\"https://pl.wikipedia.org/wiki/1414\" target=\"_blank\" rel=\"noopener noreferrer\">1414</a> roku.", "Koleta": "<b>Koleta</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Coleta</em>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>&#160;<em>Colette</em>) – pierwotnie zdrobniała forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Nikoleta\" target=\"_blank\" rel=\"noopener noreferrer\">Nikoleta</a>, powstałego od <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikoli</a>, żeńskiego odpowiednika <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaja</a>. Koleta jest imieniem znanym w Polsce, dzięki funkcjonującemu zakonowi żeńskiemu.", "Klarysa": "<b>Klarysa</b> – imię żeńskie, pokrewne imieniu <a href=\"https://pl.wikipedia.org/wiki/Klara\" target=\"_blank\" rel=\"noopener noreferrer\">Klara</a>.", "Konrada": "<b>Konrada</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Konrad_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Konrad</a> pochodzenia germańskiego.", "Klotylda": "<b>Klotylda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „słynąca w walce”.", "Kwiryna": "<b>Kwiryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kwiryn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kwiryn</a> o łacińskim pochodzeniu.", "Karena": "<b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Krzesisława": "<b>Krzesisława</b>, <b>Krzesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sława</i>. Znaczenie imienia: „odnawiająca sławę”. W zapisach staropolskich zachowała się krótsza forma <b>Krzesława</b> i zdrobniała <b>Krzechna</b> (1388 rok).", "Kajetana": "<b>Kajetana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kajetan\" target=\"_blank\" rel=\"noopener noreferrer\">Kajetan</a>. Wywodzi się od słowa oznaczającego „pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Gaeta\" target=\"_blank\" rel=\"noopener noreferrer\">Kajety</a>”, miasta w <a href=\"https://pl.wikipedia.org/wiki/Italia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Italii</a>. Patronką tego imienia jest bł. Kajetana Sterni. Na Kresach imię to było szczególnie związene z mniejszością <a href=\"https://pl.wikipedia.org/wiki/Ormianie_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańską</a>.", "Katerine": "Jej pierwszy album <i>Katerine</i> ukazał się w listopadzie 2005 roku. Znajduje się na nim hit <i>Here Come All The Boys</i>. W roku 2006 otrzymała 2 duńskie nagrody <i>Best Female Artist</i> oraz <i>Best Music Video National</i>. Rok później ukazały się jej kolejne utwory <i>Take Me Home</i> oraz <i>Catfight</i>. Następny rok przyniósł artystce występ w belgijskim odpowiedniku programu Gwiazdy tańczą na lodzie - Sterren op het Ijs. Między artystką a wytwórnią jej płyt doszło do nieporozumień, w wyniku których zmieniła wytwórnię na Mostiko.", "Kasja": "<b>Kasja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od łacińskiej nazwy rodu Kasjuszy (<i>Cassius</i>). Wśród patronów – czterech świętych.", "Karmina": "Ekstrakt koszenili to ciemnoczerwony płyn, a po wysuszeniu – proszek. Produkt handlowy barwnika występuje w połączeniu z <a href=\"https://pl.wikipedia.org/wiki/Kation\" target=\"_blank\" rel=\"noopener noreferrer\">kationami</a> <a href=\"https://pl.wikipedia.org/wiki/Jon_amonowy\" target=\"_blank\" rel=\"noopener noreferrer\">amonu</a>, wapnia, sodu i potasu, pojedynczo lub w kombinacjach. Może także zawierać materiał <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82ka\" target=\"_blank\" rel=\"noopener noreferrer\">białkowy</a> pochodzący z innych <a href=\"https://pl.wikipedia.org/wiki/Owady\" target=\"_blank\" rel=\"noopener noreferrer\">owadów</a>.", "Keiko": "<b>Keiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けいこ, ケイコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kaliksta": "<b>Kaliksta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kalikst\" target=\"_blank\" rel=\"noopener noreferrer\">Kalikst</a>. Istnieje kilka świętych katolickich o tym imieniu.", "Ksaweryna": "<b>Ksawera</b>, <b>Ksaweryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">Ksawery</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Franciszka_Ksawera\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszka Ksawera</a> Cabrini.", "Kaori": "<b>Kaori</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かおり, カオリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kasylda": "<b>Kasylda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od imienia <a href=\"https://pl.wikipedia.org/wiki/Kasja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasja</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Kasylda_z_Toledo\" target=\"_blank\" rel=\"noopener noreferrer\">Kasylda z Toledo</a>.", "Konkordia": "<b>Konkordia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Oznacza harmonię, pokój. Imię to nosiła jedna z <a href=\"https://pl.wikipedia.org/wiki/Concordia_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">bogiń</a> w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a>.", "Kalista": "<b>Kalista</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego \"najpiękniejsze\". Jest odpowiednikiem męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Kalikst\" target=\"_blank\" rel=\"noopener noreferrer\">Kalikst</a>. Istnieją dwie święte o tym imieniu.", "Kata": "<b>Kata (układ formalny)</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;型, 形&#32;<i>kata</i>&#59; standardowa forma ruchu, postawy itp. w sztukach walki i sporcie) – japońskie słowo oznaczające wysoce sformalizowany rodzaj ćwiczeń stosowanych w wielu tradycyjnych <a href=\"https://pl.wikipedia.org/wiki/Sztuki_walki\" target=\"_blank\" rel=\"noopener noreferrer\">sztukach i sportach walki</a>, szczególnie z grupy <a href=\"https://pl.wikipedia.org/wiki/Bud%C5%8D\" target=\"_blank\" rel=\"noopener noreferrer\">budō</a>, jak również <a href=\"https://pl.wikipedia.org/wiki/Taekwondo\" target=\"_blank\" rel=\"noopener noreferrer\">taekwondo</a> (gdzie noszą one nazwę <i>tul</i> w wersji <a href=\"https://pl.wikipedia.org/wiki/International_Taekwon-Do_Federation\" target=\"_blank\" rel=\"noopener noreferrer\">ITF</a>, <i>poomse</i> w <a href=\"https://pl.wikipedia.org/wiki/World_Taekwondo_Federation\" target=\"_blank\" rel=\"noopener noreferrer\">WTF</a> a <i>hyeong</i> w niektórych innych organizacjach), <a href=\"https://pl.wikipedia.org/wiki/Taijiquan\" target=\"_blank\" rel=\"noopener noreferrer\">taijiquan</a> i innych. Są to sekwencje technik ataku i obrony, połączone z określonym poruszaniem, przyjęciem ściśle określonej pozycji i sposobu oddychania. <i>Kata</i> są bardzo ważną częścią programów nauczania dla wielu <a href=\"https://pl.wikipedia.org/wiki/Sztuki_walki\" target=\"_blank\" rel=\"noopener noreferrer\">sztuk</a> i <a href=\"https://pl.wikipedia.org/wiki/Sport_walki\" target=\"_blank\" rel=\"noopener noreferrer\">sportów walki</a>, a dla niektórych, zwłaszcza tych, gdzie kontakt broni z ciałem przeciwnika stanowiłby realne zagrożenie, stanowią ćwiczenia podstawowe.", "Kapitolina": "<b>Kapitolina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od słowa oznaczającego lud łaciński, który mieszkał na <a href=\"https://pl.wikipedia.org/wiki/Kapitol\" target=\"_blank\" rel=\"noopener noreferrer\">Kapitolu</a>. Patronką tego imienia jest św. Kapitolina (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>), wspominana razem ze św. Eroteidą.", "Kana": "<b>Kana</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かな, カナ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Karuna": "W <a href=\"https://pl.wikipedia.org/wiki/Emocja\" target=\"_blank\" rel=\"noopener noreferrer\">emocjonalnym</a> rozumieniu ma znaczenie <a href=\"https://pl.wikipedia.org/wiki/Empatia\" target=\"_blank\" rel=\"noopener noreferrer\">empatycznej</a> <a href=\"https://pl.wikipedia.org/wiki/Dobro\" target=\"_blank\" rel=\"noopener noreferrer\">dobroci</a> okazywanej <a href=\"https://pl.wikipedia.org/wiki/Cierpienie\" target=\"_blank\" rel=\"noopener noreferrer\">cierpiącym</a>. W rozumieniu funkcjonalnym jest szlachetną aktywnością, jedną z <a href=\"https://pl.wikipedia.org/wiki/Paramita\" target=\"_blank\" rel=\"noopener noreferrer\">dziesięciu paramit</a> pochodzących z buddyjskiej szkoły <a href=\"https://pl.wikipedia.org/wiki/Theravada\" target=\"_blank\" rel=\"noopener noreferrer\">therawady</a>. Na duchowym poziomie jest konsekwencją i uzupełnieniem szlachetnego stanu umysłu określanego jako <a href=\"https://pl.wikipedia.org/wiki/Metta\" target=\"_blank\" rel=\"noopener noreferrer\">kochająca życzliwość</a>.", "Kiliana": "<b>Kiliana</b>, <b>Kilia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Kilian\" target=\"_blank\" rel=\"noopener noreferrer\">Kilian</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, od <i>ceallach</i> oznaczającego \"wojna\" lub <i>ceall</i> oznaczającego \"kościół\". Patronem tego imienia jest św. Kilian.", "Krescencja": "<b>Krescencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwy rodu, która z kolei pochodzi od słowa <i>crescere</i> – „wzrastać, narastać”. Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Maria_Krescencja_H%C3%B6ss\" target=\"_blank\" rel=\"noopener noreferrer\">Maria Krescencja Höss</a> (<a href=\"https://pl.wikipedia.org/wiki/1682\" target=\"_blank\" rel=\"noopener noreferrer\">1682</a>–<a href=\"https://pl.wikipedia.org/wiki/1744\" target=\"_blank\" rel=\"noopener noreferrer\">1744</a>).", "Kanako": "<b>Kanako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かなこ, カナコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kumiko": "<b>Kumiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;くみこ, クミコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Krzesława": "<b>Krzesisława</b>, <b>Krzesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sława</i>. Znaczenie imienia: „odnawiająca sławę”. W zapisach staropolskich zachowała się krótsza forma <b>Krzesława</b> i zdrobniała <b>Krzechna</b> (1388 rok).", "Kwiatosława": "<b>Florianna</b>, <b>Floriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Florian\" target=\"_blank\" rel=\"noopener noreferrer\">Florian</a>, które z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>florus</i> – „kwitnący” i oznacza „należący do <i>Florusa</i>”. <b>Florianna</b> jest nadawana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>, a po raz pierwszy zapisana była w formie <i><b>Floryjana</b></i>. Zanotowano także zdrobnienie Floszka, oraz drugie, Tworka, które mogło pochodzić od Florianny z substytucją polską (jak Florian → Tworzyjan), lub też od imion rodzimych zaczynających się na <i>Tworzy-</i>.", "Kolet": "Był długim <a href=\"https://pl.wikipedia.org/wiki/Kaftan\" target=\"_blank\" rel=\"noopener noreferrer\">kaftanem</a> lub płaszczem z długimi <a href=\"https://pl.wikipedia.org/wiki/R%C4%99kaw_(ubi%C3%B3r)\" target=\"_blank\" rel=\"noopener noreferrer\">rękawami</a> (lub bez), rozszerzanym w części dolnej. Zwykle wkładano go pod <a href=\"https://pl.wikipedia.org/wiki/Kirys\" target=\"_blank\" rel=\"noopener noreferrer\">kirys</a> (np. <a href=\"https://pl.wikipedia.org/wiki/Rajtaria\" target=\"_blank\" rel=\"noopener noreferrer\">rajtaria</a>, arkebuzeria, <a href=\"https://pl.wikipedia.org/wiki/Pikinierzy\" target=\"_blank\" rel=\"noopener noreferrer\">pikinierzy</a>) lub na wierzch jako rodzaj lżejszego ubioru ochronnego (np. u <a href=\"https://pl.wikipedia.org/wiki/Muszkieter\" target=\"_blank\" rel=\"noopener noreferrer\">muszkieterów</a>, <a href=\"https://pl.wikipedia.org/wiki/Dragoni\" target=\"_blank\" rel=\"noopener noreferrer\">dragonów</a>). Nazwa pochodzi od wywijanego skórzanego <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%82nierz\" target=\"_blank\" rel=\"noopener noreferrer\">kołnierza</a>.", "Kaho": "<b>Kaho</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かほ, カホ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kasumi": "<b>Kasumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かすみ, カスミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kandyda": "<b>Kandyda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kandyd_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kandyd</a>, oznaczające \"jasna, błyszcząca, biała\", czyli \"dziecko o jasnych włosach\" lub \"dziecko o jasnej <a href=\"https://pl.wikipedia.org/wiki/Karnacja\" target=\"_blank\" rel=\"noopener noreferrer\">cerze</a>\"; jeden z najpopularniejszych <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomków</a> rzymskich. W Polsce notowane od <a href=\"https://pl.wikipedia.org/wiki/1396\" target=\"_blank\" rel=\"noopener noreferrer\">1396</a> roku.", "Kimiko": "<b>Kimiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;きみこ, キミコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kazumi": "<b>Kazumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずみ, カズミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Kayoko": "<b>Kayoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かよこ, カヨコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kaede": "<b>Kaede</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かえで, カエデ, 楓) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Kallina": "<b>Kalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, stanowiące być może przekształcone na gruncie białoruskim imię <a href=\"https://pl.wikipedia.org/wiki/Akwilina\" target=\"_blank\" rel=\"noopener noreferrer\">Akwilina</a>, lub powstałe na gruncie wschodniosłowiańskim pod wpływem wyrazu <a href=\"https://pl.wikipedia.org/wiki/Kalina_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kalina</a>. Zgodnie z rosyjskimi źródłami, <i><b>Kalinka</b></i> to zdrobnienie zarówno męskie od <a href=\"https://pl.wikipedia.org/wiki/Kalinik\" target=\"_blank\" rel=\"noopener noreferrer\">Kalinika</a>, jak i żeńskie – od żeńskiego rosyjskiego odpowiednika tego imienia, tj. <i>Kallinikii</i> (<i>Каллиникня</i>). Należy też podkreślić, iż forma Kalina spotykana była jako męska forma skrócona imienia <a href=\"https://pl.wikipedia.org/wiki/Kalinik\" target=\"_blank\" rel=\"noopener noreferrer\">Kalinik</a> już w źródłach pochodzących z lat <a href=\"https://pl.wikipedia.org/wiki/1479\" target=\"_blank\" rel=\"noopener noreferrer\">1479</a>–<a href=\"https://pl.wikipedia.org/wiki/1584\" target=\"_blank\" rel=\"noopener noreferrer\">1584</a> z <a href=\"https://pl.wikipedia.org/wiki/Monastyr_So%C5%82owiecki\" target=\"_blank\" rel=\"noopener noreferrer\">monastyru sołowieckiego</a>.", "Kokila": "<b>Kokila</b> – metalowa <a href=\"https://pl.wikipedia.org/wiki/Forma_odlewnicza\" target=\"_blank\" rel=\"noopener noreferrer\">forma odlewnicza</a>, do której wlewa się roztopiony metal (często pod ciśnieniem). Kokila jest formą wielokrotnego użytku. Może być zalewana <a href=\"https://pl.wikipedia.org/wiki/Odlewanie_od%C5%9Brodkowe\" target=\"_blank\" rel=\"noopener noreferrer\">odśrodkowo</a> lub grawitacyjnie.", "Klemencja": "<b>Klemencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Klemens\" target=\"_blank\" rel=\"noopener noreferrer\">Klemens</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/21_marca\" target=\"_blank\" rel=\"noopener noreferrer\">21&#160;marca</a>.", "Kalia": "<b>Cantedeskia</b>, kalijka, kalia (<i>Zantedeschia</i> Spreng.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Obrazkowate\" target=\"_blank\" rel=\"noopener noreferrer\">obrazkowatych</a>, obejmujący 8 <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a> pochodzących ze środkowo-południowej <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>, z jednym gatunkiem introdukowanym na wszystkich kontynentach z wyjątkiem Antarktydy. Z uwagi na bardzo atrakcyjne kwiatostany i ulistnienie cantedeskie, zarówno gatunki botaniczne, jak i ich <a href=\"https://pl.wikipedia.org/wiki/Kultywar\" target=\"_blank\" rel=\"noopener noreferrer\">kultywary</a>, są szeroko uprawiane na świecie jako <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny_ozdobne\" target=\"_blank\" rel=\"noopener noreferrer\">rośliny ozdobne</a>.", "Kehlani": "Kehlani pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Oakland\" target=\"_blank\" rel=\"noopener noreferrer\">Oakland</a> w <a href=\"https://pl.wikipedia.org/wiki/Kalifornia\" target=\"_blank\" rel=\"noopener noreferrer\">Kalifornii</a>, gdzie osiągnęła początkową sławę jako członek grupy popowej Poplyfe, która była finalistą <a href=\"https://pl.wikipedia.org/wiki/America%E2%80%99s_Got_Talent\" target=\"_blank\" rel=\"noopener noreferrer\">America’s Got Talent</a>. W 2014 roku wydała swój pierwszy <a href=\"https://pl.wikipedia.org/wiki/Mixtape\" target=\"_blank\" rel=\"noopener noreferrer\">mixtape</a> <i>Cloud 19</i>. Album ten znalazł się na liście 50 najlepszych albumów w 2014 stworzonej przez Complex&#65279;<a href=\"https://www.wikidata.org/wiki/Q5156550#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>. Drugi <a href=\"https://pl.wikipedia.org/wiki/Mixtape\" target=\"_blank\" rel=\"noopener noreferrer\">mixtape</a> Kehlani, <i>You Should Be Here</i>, zadebiutował jako 5 na amerykańskim rankingu R&amp;B/Hip-Hop w roku 2015. Poprzedził on wyprzedaną trasę koncertową po <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Północnej Ameryce</a>. W 2016 roku jej album <i>You should be here</i> został nominowany do <a href=\"https://pl.wikipedia.org/wiki/Nagroda_Grammy\" target=\"_blank\" rel=\"noopener noreferrer\">nagrody Grammy</a> jako Best Urban Contemporary Album. Debiutancki album studyjny Kehlani, <i>SweetSexySavage</i>, został wydany 27 stycznia 2017 roku.", "Keremet": "<b>Keremet</b> – bóstwo panteonu Finów permskich (<a href=\"https://pl.wikipedia.org/wiki/Udmurci\" target=\"_blank\" rel=\"noopener noreferrer\">Udmurtów</a>). Nazwa zapożyczona od ludów tureckich oznaczająca \"ducha ważnej osobistości\". Nazywany również Łudem lub Szajtenem. Przeciwieństwo dobrego – Inmara, jednak o podobnej mocy. Inmar był prawdopodobnie jego bratem. Keremet jest zły i inteligentny. Panuje nad światem podziemnym i złymi duchami. Razem ze swoim bratem brał czynny udział w stwarzaniu ziemi. Inmar wysłał go po odrobinę gleby z dna morskiego, by z niej stworzyć świat. Rysuje się tu znany motyw kosmogoniczny: świat zostaje stworzony przy współpracy dobrego i złego boga, i to zły dokonuje zanurzenia w morzu, gdyż to on sprawuje nad nim władzę. Z kawałka ziemi ukrytej przed Inmarem w ustach, Keremet stwarza góry. Jest on również przyczyną unicestwienia lub wygnania pierwszych ludzi, gdyż za jego namową spożywają oni napój zabroniony przez Inamara – <a href=\"https://pl.wikipedia.org/wiki/Kumys\" target=\"_blank\" rel=\"noopener noreferrer\">kumys</a>. W świętych gajach (również nazywanych keremetami lub łudami) składano mu w ofierze zwierzęta o czarnej sierści.", "Kanizja": "<b>Kanizja</b> – imię żeńskie pochodzące od nazwiska św. <a href=\"https://pl.wikipedia.org/wiki/Piotr_Kanizjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Piotra Kanizjusza</a>, doktora Kościoła. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiona\" target=\"_blank\" rel=\"noopener noreferrer\">bł.</a> <a href=\"https://pl.wikipedia.org/wiki/Maria_Kanizja\" target=\"_blank\" rel=\"noopener noreferrer\">Maria Kanizja</a> (Eugenia Mackiewicz), siostra nazaretanka, wspominana razem z bł. Marią Stellą i innymi towarzyszkami.", "Krzysztosława": "Etymologia imienia nie jest jasna, podawane są dwie hipotezy dotyczące jego pochodzenia. Według pierwszej jest to imię wywodzące się z czasów pogańskich i z tradycji słowiańskiej, które do dziś przetrwało w lekko zmienionej formie. Druga mówi, że pochodzi ono od imienia <i>Krzysztof</i>, które na terenach Grecji we wczesnych czasach chrześcijańskich oznaczało gorliwego wyznawcę religii chrystusowej, człowieka nawróconego, co mogłoby sugerować, że znaczenie imienia <i>Krzysztosława</i> to <i>sławiąca wyznawców Chrystusa</i>.", "Kumi": "<b>Kumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;くみ, クミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kwieta": "<b>Kwieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „spokojna”. Patronką tego imienia jest św. Kwieta, wspominana według jednych źródeł wspólnie ze św. Teodorą, zaś zgodnie z innymi – ze św. Hilarym, swoim mężem.", "Kiyoko": "<b>Kiyoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;きよこ, キヨコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kismet": "<b>Kismet</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">tureckie</a> słowo oznaczające <a href=\"https://pl.wikipedia.org/wiki/Przeznaczenie\" target=\"_blank\" rel=\"noopener noreferrer\">przeznaczenie</a>, <a href=\"https://pl.wikipedia.org/wiki/Fatum\" target=\"_blank\" rel=\"noopener noreferrer\">fatum</a>, los. Używane przez <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskie</a> ludy tureckie oraz na terenach pozostających przez wieki pod tureckim panowaniem (<a href=\"https://pl.wikipedia.org/wiki/Bo%C5%9Bnia_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Bośnia</a>, <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacja</a>, <a href=\"https://pl.wikipedia.org/wiki/Serbia\" target=\"_blank\" rel=\"noopener noreferrer\">Serbia</a>, <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgaria</a>).", "Kaliope": "Imieniem muzy została nazwana jedna z planetoid – <a href=\"https://pl.wikipedia.org/wiki/(22)_Kalliope\" target=\"_blank\" rel=\"noopener noreferrer\">(22) Kalliope</a>.", "Kwietosława": "<b>Florianna</b>, <b>Floriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Florian\" target=\"_blank\" rel=\"noopener noreferrer\">Florian</a>, które z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>florus</i> – „kwitnący” i oznacza „należący do <i>Florusa</i>”. <b>Florianna</b> jest nadawana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>, a po raz pierwszy zapisana była w formie <i><b>Floryjana</b></i>. Zanotowano także zdrobnienie Floszka, oraz drugie, Tworka, które mogło pochodzić od Florianny z substytucją polską (jak Florian → Tworzyjan), lub też od imion rodzimych zaczynających się na <i>Tworzy-</i>.", "Kartini": "Pochodziła z jawajskiej rodziny <a href=\"https://pl.wikipedia.org/wiki/Arystokracja\" target=\"_blank\" rel=\"noopener noreferrer\">arystokratycznej</a>, otrzymała zachodnie wykształcenie. Podkreślała konieczność <a href=\"https://pl.wikipedia.org/wiki/Edukacja_kobiet\" target=\"_blank\" rel=\"noopener noreferrer\">edukacji kobiet</a>, występowała przeciwko <a href=\"https://pl.wikipedia.org/wiki/Poligamia\" target=\"_blank\" rel=\"noopener noreferrer\">poligamii</a> i <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82%C5%BCe%C5%84stwa_dzieci\" target=\"_blank\" rel=\"noopener noreferrer\">dziecięcym małżeństwom</a>. Zmarła przy porodzie. Opublikowano, pod tytułem <i>Z ciemności w jasność</i>, zbiór listów jej autorstwa. Książka ta przyczyniła się do popularyzacji poglądów Kartini. Powstały również, z inicjatywy jej zwolenników, szkoły dla kobiet, zwane szkołami Kartini.", "Katiusza": "<i>Katiusza</i> to zdrobnienie popularnego w Rosji żeńskiego imienia Jekatierina (<a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>), „Kasieńka”, „Kaśka” – taki też tytuł nosiła popularna podczas wojny w Związku Radzieckim <a href=\"https://pl.wikipedia.org/wiki/Katiusza_(utw%C3%B3r)\" target=\"_blank\" rel=\"noopener noreferrer\">piosenka</a> mówiąca o tęsknocie dziewczyny do ukochanego, który odbywa służbę wojskową."};
